using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        // Calculate header metrics
        var totalValue = holdings.Sum(h => h.TotalValue);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken);
            var totalValue = holding.Quantity * currentPrice;
            var totalInvested = holding.Quantity * holding.AverageCost;

            var holdingDto = new HoldingDto
            {
                Id = holding.Id,
                Ticker = holding.Ticker,
                EtfName = holding.EtfName,
                Quantity = holding.Quantity,
                AverageCost = holding.AverageCost,
                CurrentPrice = currentPrice,
                TotalValue = totalValue,
                DailyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 1, cancellationToken),
                WeeklyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 7, cancellationToken),
                MonthlyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 30, cancellationToken),
                YtdMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, DaysSinceYearStart(), cancellationToken)
            };

            holdingDtos.Add(holdingDto);
        }

        return holdingDtos;
    }

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderByDescending(t => t.PurchaseDate)
            .Select(t => new TransactionDto
            {
                Id = t.Id,
                HoldingId = t.HoldingId,
                Quantity = t.Quantity,
                PurchasePrice = t.PurchasePrice,
                PurchaseDate = t.PurchaseDate,
                CreatedAt = t.CreatedAt
            })
            .ToListAsync(cancellationToken);

        return transactions;
    }

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var transaction = await _context.Database.BeginTransactionAsync(cancellationToken);

        try
        {
            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                holding = new Holding
                {
                    UserId = userId,
                    Ticker = dto.Ticker,
                    Quantity = 0,
                    AverageCost = 0
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Add transaction
            var newTransaction = new Transaction
            {
                HoldingId = holding.Id,
                Quantity = dto.Quantity,
                PurchasePrice = dto.PurchasePrice,
                PurchaseDate = dto.PurchaseDate
            };
            _context.Transactions.Add(newTransaction);
            await _context.SaveChangesAsync(cancellationToken);

            // Update holding average cost and quantity
            var allTransactions = await _context.Transactions
                .Where(t => t.HoldingId == holding.Id)
                .ToListAsync(cancellationToken);

            var totalQuantity = allTransactions.Sum(t => t.Quantity);
            var totalCost = allTransactions.Sum(t => t.Quantity * t.PurchasePrice);

            holding.Quantity = totalQuantity;
            holding.AverageCost = totalQuantity > 0 ? totalCost / totalQuantity : 0;
            holding.UpdatedAt = DateTime.UtcNow;

            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);

            await transaction.CommitAsync(cancellationToken);
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal totalInvested, int days, CancellationToken cancellationToken)
    {
        var currentPrice = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!priceFromDaysAgo.HasValue)
        {
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0 };
        }

        var totalValue = Decimal.MaxValue; // Quantity would be needed, using placeholder
        var gainLossEur = totalValue - totalInvested;
        var gainLossPercent = priceFromDaysAgo.Value > 0 
            ? ((currentPrice - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100 
            : 0;

        return new PeriodMetrics
        {
            GainLossEur = gainLossEur,
            GainLossPercent = gainLossPercent
        };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        // Try to get exact date first
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null)
            return snapshot.Price;

        // If not found, get the closest earlier snapshot
        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;

        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private int DaysSinceYearStart()
    {
        var today = DateTime.UtcNow.Date;
        var yearStart = new DateTime(today.Year, 1, 1);
        return (today - yearStart).Days;
    }
}

using Microsoft.EntityFrameworkCore;
using ETFTracker.Api.Data;
using ETFTracker.Api.Dtos;
using ETFTracker.Api.Models;

namespace ETFTracker.Api.Services;

public interface IHoldingsService
{
    Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default);
    Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default);
    Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default);
}

public class HoldingsService : IHoldingsService
{
    private readonly AppDbContext _context;
    private readonly IPriceService _priceService;
    private readonly ILogger<HoldingsService> _logger;

    public HoldingsService(AppDbContext context, IPriceService priceService, ILogger<HoldingsService> logger)
    {
        _context = context;
        _priceService = priceService;
        _logger = logger;
    }

    public async Task<DashboardDto> GetDashboardAsync(int userId, CancellationToken cancellationToken = default)
    {
        var holdings = await GetHoldingsAsync(userId, cancellationToken);

        var dashboard = new DashboardDto();

        // Calculate header metrics
        var totalValue = holdings.Sum(h => h.TotalValue);
        dashboard.Header.TotalHoldingsAmount = totalValue;

        dashboard.Header.DailyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.DailyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.DailyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.WeeklyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.WeeklyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.WeeklyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.MonthlyMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.MonthlyMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.MonthlyMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Header.YtdMetrics = new PeriodMetrics
        {
            GainLossEur = holdings.Sum(h => h.YtdMetrics.GainLossEur),
            GainLossPercent = CalculateWeightedPercentage(holdings, h => h.YtdMetrics.GainLossPercent, h => h.TotalValue)
        };

        dashboard.Holdings = holdings;
        return dashboard;
    }

    public async Task<List<HoldingDto>> GetHoldingsAsync(int userId, CancellationToken cancellationToken = default)
    {
        var dbHoldings = await _context.Holdings
            .Where(h => h.UserId == userId)
            .Include(h => h.Transactions)
            .OrderBy(h => h.Ticker)
            .ToListAsync(cancellationToken);

        var holdingDtos = new List<HoldingDto>();

        foreach (var holding in dbHoldings)
        {
            var currentPrice = await _priceService.GetPriceAsync(holding.Ticker, cancellationToken);
            var totalValue = holding.Quantity * currentPrice;
            var totalInvested = holding.Quantity * holding.AverageCost;

            var holdingDto = new HoldingDto
            {
                Id = holding.Id,
                Ticker = holding.Ticker,
                EtfName = holding.EtfName,
                Quantity = holding.Quantity,
                AverageCost = holding.AverageCost,
                CurrentPrice = currentPrice,
                TotalValue = totalValue,
                DailyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 1, cancellationToken),
                WeeklyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 7, cancellationToken),
                MonthlyMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, 30, cancellationToken),
                YtdMetrics = await CalculatePeriodMetricsAsync(holding.Ticker, totalInvested, DaysSinceYearStart(), cancellationToken)
            };

            holdingDtos.Add(holdingDto);
        }

        return holdingDtos;
    }

    public async Task<List<TransactionDto>> GetHoldingHistoryAsync(int holdingId, CancellationToken cancellationToken = default)
    {
        var transactions = await _context.Transactions
            .Where(t => t.HoldingId == holdingId)
            .OrderByDescending(t => t.PurchaseDate)
            .Select(t => new TransactionDto
            {
                Id = t.Id,
                HoldingId = t.HoldingId,
                Quantity = t.Quantity,
                PurchasePrice = t.PurchasePrice,
                PurchaseDate = t.PurchaseDate,
                CreatedAt = t.CreatedAt
            })
            .ToListAsync(cancellationToken);

        return transactions;
    }

    public async Task AddTransactionAsync(int userId, CreateTransactionDto dto, CancellationToken cancellationToken = default)
    {
        using var transaction = await _context.Database.BeginTransactionAsync(cancellationToken);

        try
        {
            // Get or create holding
            var holding = await _context.Holdings
                .FirstOrDefaultAsync(h => h.UserId == userId && h.Ticker == dto.Ticker, cancellationToken);

            if (holding == null)
            {
                holding = new Holding
                {
                    UserId = userId,
                    Ticker = dto.Ticker,
                    Quantity = 0,
                    AverageCost = 0
                };
                _context.Holdings.Add(holding);
                await _context.SaveChangesAsync(cancellationToken);
            }

            // Add transaction
            var newTransaction = new Transaction
            {
                HoldingId = holding.Id,
                Quantity = dto.Quantity,
                PurchasePrice = dto.PurchasePrice,
                PurchaseDate = dto.PurchaseDate
            };
            _context.Transactions.Add(newTransaction);
            await _context.SaveChangesAsync(cancellationToken);

            // Update holding average cost and quantity
            var allTransactions = await _context.Transactions
                .Where(t => t.HoldingId == holding.Id)
                .ToListAsync(cancellationToken);

            var totalQuantity = allTransactions.Sum(t => t.Quantity);
            var totalCost = allTransactions.Sum(t => t.Quantity * t.PurchasePrice);

            holding.Quantity = totalQuantity;
            holding.AverageCost = totalQuantity > 0 ? totalCost / totalQuantity : 0;
            holding.UpdatedAt = DateTime.UtcNow;

            _context.Holdings.Update(holding);
            await _context.SaveChangesAsync(cancellationToken);

            await transaction.CommitAsync(cancellationToken);
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync(cancellationToken);
            _logger.LogError(ex, "Error adding transaction");
            throw;
        }
    }

    private async Task<PeriodMetrics> CalculatePeriodMetricsAsync(string ticker, decimal quantity, int days, CancellationToken cancellationToken)
    {
        var currentPrice = await _priceService.GetPriceAsync(ticker, cancellationToken);
        var priceFromDaysAgo = await GetPriceFromDaysAgoAsync(ticker, days, cancellationToken);

        if (!priceFromDaysAgo.HasValue)
        {
            return new PeriodMetrics { GainLossEur = 0, GainLossPercent = 0 };
        }

        var gainLossEur = (currentPrice - priceFromDaysAgo.Value) * quantity;
        var gainLossPercent = priceFromDaysAgo.Value > 0 
            ? ((currentPrice - priceFromDaysAgo.Value) / priceFromDaysAgo.Value) * 100 
            : 0;

        return new PeriodMetrics
        {
            GainLossEur = gainLossEur,
            GainLossPercent = gainLossPercent
        };
    }

    private async Task<decimal?> GetPriceFromDaysAgoAsync(string ticker, int days, CancellationToken cancellationToken)
    {
        var targetDate = DateTime.UtcNow.AddDays(-days).Date;

        // Try to get exact date first
        var snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate == targetDate)
            .OrderByDescending(ps => ps.CreatedAt)
            .FirstOrDefaultAsync(cancellationToken);

        if (snapshot != null)
            return snapshot.Price;

        // If not found, get the closest earlier snapshot
        snapshot = await _context.PriceSnapshots
            .Where(ps => ps.Ticker == ticker && ps.SnapshotDate < targetDate)
            .OrderByDescending(ps => ps.SnapshotDate)
            .FirstOrDefaultAsync(cancellationToken);

        return snapshot?.Price;
    }

    private decimal CalculateWeightedPercentage(List<HoldingDto> holdings, Func<HoldingDto, decimal> percentSelector, Func<HoldingDto, decimal> weightSelector)
    {
        var totalWeight = holdings.Sum(weightSelector);
        if (totalWeight <= 0) return 0;

        return holdings.Sum(h => (percentSelector(h) / 100m) * weightSelector(h)) / totalWeight * 100;
    }

    private int DaysSinceYearStart()
    {
        var today = DateTime.UtcNow.Date;
        var yearStart = new DateTime(today.Year, 1, 1);
        return (today - yearStart).Days;
    }
}

// Top-level menu that splits dashboard into Portfolio and Projections views.
.main-menu-nav {
  display: flex;
  gap: 0.75rem;
  margin: 0 0 1.25rem;
  padding: 0.35rem;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(16, 185, 129, 0.18);
  border-radius: 12px;
}

.main-menu-btn {
  flex: 1;
  min-width: 0;
  border: 1px solid transparent;
  background: transparent;
  color: var(--text-secondary);
  font-weight: 700;
  font-size: 0.92rem;
  border-radius: 9px;
  padding: 0.65rem 0.9rem;
  cursor: pointer;
  transition: all 0.2s ease;

  &:hover {
    color: #FFFFFF;
    background: rgba(16, 185, 129, 0.1);
  }

  &.active {
    color: #FFFFFF;
    background: linear-gradient(135deg, rgba(16, 185, 129, 0.25) 0%, rgba(5, 150, 105, 0.22) 100%);
    border-color: rgba(16, 185, 129, 0.45);
    box-shadow: 0 0 0 1px rgba(16, 185, 129, 0.2) inset;
  }
}

@media (max-width: 768px) {
  .main-menu-nav {
    gap: 0.5rem;
    padding: 0.3rem;
  }

  .main-menu-btn {
    font-size: 0.85rem;
    padding: 0.55rem 0.65rem;
  }
}

// ── STICKY HEADER WRAPPER ────────────────────────────────────────────────────
// Wraps both the viewing-as banner and the nav so they stick together at top.
.sticky-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  margin: -2rem -2.5rem 2rem -2.5rem;

  @media (max-width: 768px) {
    margin: -2rem -1rem 1.5rem -1rem;
  }
}

// ── VIEWING-AS BANNER ────────────────────────────────────────────────────────
.viewing-as-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.7rem 2.5rem;
  background: linear-gradient(135deg, rgba(16, 185, 129, 0.15) 0%, rgba(5, 150, 105, 0.15) 100%);
  border-bottom: 1px solid rgba(16, 185, 129, 0.3);

  .viewing-as-label {
    font-size: 0.9rem;
    color: var(--text-secondary);
    display: flex;
    align-items: center;
    gap: 0.6rem;

    strong { color: #10B981; }

    .readonly-chip {
      font-size: 0.75rem;
      padding: 0.15rem 0.55rem;
      background: rgba(248, 155, 41, 0.15);
      color: #f89b29;
      border-radius: 999px;
      border: 1px solid rgba(248, 155, 41, 0.3);
    }
  }

  .btn-stop-viewing {
    flex-shrink: 0;
    padding: 0.4rem 0.9rem;
    background: rgba(255, 255, 255, 0.07);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 8px;
    color: var(--text-secondary);
    font-size: 0.83rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;

    &:hover {
      background: rgba(255, 255, 255, 0.12);
      color: #fff;
    }
  }

  @media (max-width: 768px) {
    padding: 0.6rem 1rem;
    flex-wrap: wrap;
  }
}

// ── TOP NAVIGATION ──────────────────────────────────────────────────────────
.top-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2.5rem;
  background: linear-gradient(135deg, #1E293B 0%, #1E293B 100%);
  border-bottom: 1px solid var(--border);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3);
  // sticky + margins moved to .sticky-header wrapper

  .nav-left {
    flex: 0 0 auto;

    .app-brand {
      font-size: 1.05rem;
      font-weight: 800;
      color: var(--text-primary);
      letter-spacing: -0.02em;
      display: flex;
      align-items: center;
      gap: 0.6rem;

      &__logo {
        height: 36px;
        width: auto;
        object-fit: contain;
        display: block;
      }
    }
  }

  .nav-right {
    flex: 0 0 auto;

    .user-menu {
      display: flex;
      align-items: center;
      gap: 1.25rem;
      padding: 0.5rem 1rem 0.5rem 1.25rem;
      background: rgba(255, 255, 255, 0.03);
      border: 1px solid rgba(16, 185, 129, 0.1);
      border-radius: 12px;
      transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);

      &:hover {
        background: rgba(255, 255, 255, 0.06);
        border-color: rgba(16, 185, 129, 0.25);
        box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.08);
      }

      .user-info {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        min-width: 0;

        .avatar-wrapper {
          flex-shrink: 0;
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background: var(--bg-elevated);
          border: 2px solid var(--border-light);
          overflow: hidden;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: all 0.2s;

          .avatar {
            width: 100%;
            height: 100%;
            object-fit: cover;
          }

          .avatar-placeholder {
            width: 100%;
            height: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            font-size: 1rem;
            background: linear-gradient(135deg, var(--accent-purple) 0%, var(--accent) 100%);
            color: #fff;
          }

          &:hover {
            border-color: var(--accent);
            box-shadow: 0 0 0 2px rgba(16, 185, 129, 0.2);
            transform: scale(1.05);
          }
        }

        .user-details {
          display: flex;
          flex-direction: column;
          gap: 0.15rem;
          min-width: 0;

          .user-name {
            font-weight: 600;
            font-size: 0.95rem;
            color: var(--text-primary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }

          .user-email {
            font-size: 0.78rem;
            color: var(--text-secondary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }
        }
      }

      .btn-share {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(5, 150, 105, 0.12);
        color: #a78bfa;
        border: 1px solid rgba(5, 150, 105, 0.25);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .share-text { display: inline; }

        &:hover {
          background: rgba(5, 150, 105, 0.22);
          border-color: rgba(5, 150, 105, 0.45);
          color: #c4b5fd;
          transform: translateY(-1px);
        }
      }

      .btn-settings {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(16, 185, 129, 0.10);
        color: #93c5fd;
        border: 1px solid rgba(16, 185, 129, 0.22);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .settings-text { display: inline; }

        &:hover {
          background: rgba(16, 185, 129, 0.22);
          border-color: rgba(16, 185, 129, 0.45);
          color: #bfdbfe;
          transform: translateY(-1px);
        }
      }

      .btn-logout {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.4rem;
        padding: 0.45rem 0.9rem;
        background: rgba(240, 82, 82, 0.08);
        color: #f05252;
        border: 1px solid rgba(240, 82, 82, 0.22);
        border-radius: 8px;
        font-size: 0.83rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .logout-icon { font-size: 0.95rem; }
        .logout-text { display: inline; }

        &:hover {
          background: rgba(240, 82, 82, 0.18);
          border-color: rgba(240, 82, 82, 0.5);
          color: #ff6b6b;
          transform: translateY(-1px);
        }
      }

      // ── Irish Investor Toggle ──────────────────────────────────────────────
      .irish-investor-toggle {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.4rem 0.75rem;
        background: rgba(255, 255, 255, 0.04);
        border: 1px solid rgba(255, 255, 255, 0.1);
        border-radius: 8px;
        cursor: pointer;
        transition: all 0.2s;
        user-select: none;

        .irish-toggle-label {
          font-size: 0.78rem;
          font-weight: 600;
          color: var(--text-secondary);
          white-space: nowrap;
          transition: color 0.2s;
        }

        .irish-toggle-track {
          position: relative;
          width: 30px;
          height: 16px;
          background: rgba(255, 255, 255, 0.1);
          border-radius: 16px;
          transition: background 0.2s;
          flex-shrink: 0;

          .irish-toggle-thumb {
            position: absolute;
            top: 2px;
            left: 2px;
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background: #E5E7EB;
            transition: transform 0.2s, background 0.2s;
          }
        }

        &.active {
          background: rgba(16, 185, 129, 0.08);
          border-color: rgba(16, 185, 129, 0.3);

          .irish-toggle-label {
            color: #10B981;
          }

          .irish-toggle-track {
            background: rgba(16, 185, 129, 0.25);

            .irish-toggle-thumb {
              transform: translateX(14px);
              background: #10B981;
            }
          }
        }

        &:hover {
          background: rgba(16, 185, 129, 0.12);
          border-color: rgba(16, 185, 129, 0.4);
        }
      }
    }
  }

  @media (max-width: 768px) {
    padding: 0.8rem 1rem;
    flex-wrap: wrap;
    gap: 0.75rem;

    .nav-left .app-brand {
      font-size: 1.1rem;
    }

    .nav-right .user-menu {
      gap: 0.75rem;
      padding: 0.4rem 0.8rem;

      .user-info .avatar-wrapper {
        width: 36px;
        height: 36px;
      }

      .user-details {
        display: none;
      }

      .btn-share .share-text {
        display: none;
      }

      .btn-settings .settings-text {
        display: none;
      }

      .btn-logout {
        padding: 0.4rem 0.8rem;
        font-size: 0.78rem;

        .logout-text {
          display: none;
        }
      }

      .irish-investor-toggle .irish-toggle-label {
        display: none;
      }
    }
  }
}

// ── Shared helpers ──────────────────────────────────────────────────────────
%card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
}

%section-heading {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;

  &::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 1em;
    border-radius: 2px;
    background: var(--accent);
  }
}

// ── Sortable table header ───────────────────────────────────────────────────
th.sortable {
  cursor: pointer;
  user-select: none;
  white-space: nowrap;

  &::after {
    content: ' ⇅';
    font-size: 0.7em;
    opacity: 0.35;
    transition: opacity 0.15s;
  }

  &:hover::after { opacity: 0.7; }

  &.sort-asc::after  { content: ' ▲'; opacity: 0.85; color: var(--accent); }
  &.sort-desc::after { content: ' ▼'; opacity: 0.85; color: var(--accent); }

  &:hover { color: var(--accent); }
}

// ── Dashboard shell ─────────────────────────────────────────────────────────
.dashboard-container {
  padding: 2rem 2.5rem;
  max-width: 1700px;
  margin: 0 auto;

  // Loading & error states
  .loading, .error {
    text-align: center;
    padding: 4rem 2rem;
    font-size: 1rem;
    color: var(--text-secondary);

    button {
      margin-top: 1.25rem;
      padding: 0.6rem 1.75rem;
      background: var(--accent);
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      transition: background 0.2s;

      &:hover { background: var(--accent-hover); }
    }
  }

  .error {
    @extend %card;
    color: var(--negative);
    border-color: rgba(240, 82, 82, 0.3);
    background: rgba(240, 82, 82, 0.06);
  }

  // ── Dashboard content ──────────────────────────────────────────────────────
  .dashboard-content {

    // ── HEADER ────────────────────────────────────────────────────────────────
    .dashboard-header {
      margin-bottom: 2.5rem;

      h1 {
        font-size: 1.65rem;
        font-weight: 800;
        letter-spacing: -0.03em;
        color: var(--text-primary);
        margin-bottom: 1.75rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        &::after {
          content: '';
          flex: 1;
          height: 1px;
          background: var(--border);
        }
      }

      // Metric cards grid
      .metrics-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 1rem;
        margin-bottom: 1.5rem;

        .metric-card {
          @extend %card;
          padding: 1.35rem 1.5rem;
          position: relative;
          overflow: hidden;
          transition: transform 0.18s, box-shadow 0.18s;

          &::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2px;
            background: var(--border-light);
            transition: background 0.2s;
          }

          &:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 28px rgba(0,0,0,0.55);
            &::before { background: var(--accent); }
          }

          .metric-label {
            font-size: 0.72rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .exclamation-mark {
              display: inline-flex;
              align-items: center;
              justify-content: center;
              width: 1.15rem;
              height: 1.15rem;
              background: var(--negative);
              color: #fff;
              border-radius: 50%;
              font-size: 0.7rem;
              font-weight: 700;
              flex-shrink: 0;
            }
          }

          .metric-value {
            font-size: 1.65rem;
            font-weight: 800;
            letter-spacing: -0.03em;
            color: var(--text-primary);
            margin-bottom: 0.25rem;
            font-variant-numeric: tabular-nums;
          }

          .metric-percent {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-secondary);
          }

          .price-unavailable-message {
            font-size: 0.75rem;
            color: var(--negative);
            margin-top: 0.6rem;
            font-style: italic;
            background: var(--negative-bg);
            padding: 0.35rem 0.6rem;
            border-radius: 5px;
          }

          // Total Holdings – blue gradient hero card
          &.total {
            background: linear-gradient(135deg, #1a3a6e 0%, #0f224d 100%);
            border-color: rgba(16, 185, 129, 0.3);

            &::before { background: var(--accent); }

            .metric-label { color: rgba(228, 234, 245, 0.6); }
            .metric-value { color: #fff; font-size: 1.9rem; }
          }

          &.positive {
            .metric-value, .metric-percent { color: var(--positive); }
            &::before { background: var(--positive); }
          }

          &.negative {
            .metric-value, .metric-percent { color: var(--negative); }
            &::before { background: var(--negative); }
          }
        }
      }

      .action-buttons {
        display: flex;
        gap: 0.75rem;

        .btn {
          padding: 0.55rem 1.35rem;
          font-size: 0.88rem;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;
            box-shadow: 0 0 0 0 var(--accent-glow);

            &:hover {
              background: var(--accent-hover);
              box-shadow: 0 0 0 4px var(--accent-glow);
            }
          }
        }
      }
    }

    // ── PROJECTION SECTION ─────────────────────────────────────────────────
    .projection-section {
      @extend %card;
      padding: 1.75rem;
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Parameter inputs row
      .projection-params {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-end;
        gap: 1rem;
        margin-bottom: 1.75rem;
        padding: 1.25rem;
        background: var(--bg-surface);
        border: 1px solid var(--border);
        border-radius: 8px;

        .param-group {
          display: flex;
          flex-direction: column;
          gap: 0.35rem;

          label {
            font-size: 0.68rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.07em;
          }

          input[type='number'] {
            width: 130px;
            padding: 0.5rem 0.7rem;
            border: 1px solid var(--border-light);
            border-radius: 7px;
            font-size: 0.9rem;
            color: var(--text-primary);
            background: var(--bg-input);
            transition: border-color 0.18s, box-shadow 0.18s;
            font-variant-numeric: tabular-nums;

            &:focus {
              outline: none;
              border-color: var(--accent);
              box-shadow: 0 0 0 3px var(--accent-glow);
            }
          }

          &.checkbox-group {
            justify-content: flex-end;

            .checkbox-label {
              display: flex;
              align-items: center;
              gap: 0.5rem;
              font-size: 0.82rem;
              font-weight: 500;
              color: var(--text-secondary);
              text-transform: none;
              letter-spacing: normal;
              cursor: pointer;
              white-space: nowrap;

              input[type='checkbox'] {
                width: 16px;
                height: 16px;
                accent-color: var(--accent);
                cursor: pointer;
              }
            }

            .setting-toggle {
              display: inline-flex;
              align-items: center;
              gap: 0.75rem;
              padding: 0.45rem 0.7rem;
              border: 1px solid var(--border-light);
              border-radius: 999px;
              background: rgba(255, 255, 255, 0.03);
              color: var(--text-secondary);
              cursor: pointer;
              transition: all 0.18s ease;

              .setting-toggle-label {
                font-size: 0.82rem;
                font-weight: 500;
                color: inherit;
                text-transform: none;
                letter-spacing: normal;
                white-space: nowrap;
              }

              .setting-toggle-track {
                position: relative;
                width: 34px;
                height: 18px;
                border-radius: 999px;
                background: rgba(255, 255, 255, 0.12);
                transition: background 0.18s ease;
                flex-shrink: 0;

                .setting-toggle-thumb {
                  position: absolute;
                  top: 2px;
                  left: 2px;
                  width: 14px;
                  height: 14px;
                  border-radius: 50%;
                  background: #E5E7EB;
                  transition: transform 0.18s ease, background 0.18s ease;
                }
              }

              &:hover {
                border-color: rgba(16, 185, 129, 0.45);
                background: rgba(16, 185, 129, 0.08);
                color: var(--text-primary);
              }

              &:focus-visible {
                outline: none;
                box-shadow: 0 0 0 3px var(--accent-glow);
                border-color: var(--accent);
              }

              &.active {
                border-color: rgba(16, 185, 129, 0.35);
                background: rgba(16, 185, 129, 0.08);
                color: var(--text-primary);

                .setting-toggle-track {
                  background: rgba(16, 185, 129, 0.24);

                  .setting-toggle-thumb {
                    transform: translateX(16px);
                    background: #10B981;
                  }
                }
              }
            }
          }

          &.start-amount-group {
            .start-amount-input-row {
              display: flex;
              align-items: center;
              gap: 0.4rem;

              input[type='number'] {
                width: 130px;
              }

              .btn-copy-portfolio {
                flex-shrink: 0;
                display: flex;
                align-items: center;
                justify-content: center;
                width: 32px;
                height: 32px;
                padding: 0;
                background: var(--bg-elevated);
                border: 1px solid var(--border-light);
                border-radius: 7px;
                font-size: 0.9rem;
                cursor: pointer;
                transition: all 0.18s;
                color: var(--text-secondary);

                &:hover {
                  background: rgba(16, 185, 129, 0.12);
                  border-color: var(--accent);
                  color: var(--accent);
                  transform: scale(1.1);
                }

                &:active {
                  transform: scale(0.96);
                }
              }
            }

            .start-amount-hint {
              font-size: 0.65rem;
              color: var(--text-muted);
              font-style: italic;
              margin-top: 0.15rem;
              display: block;
            }
          }
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }

          &.btn-secondary {
            background: transparent;
            border: 1px solid var(--accent);
            color: var(--accent);

            &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.10); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }

        .save-version-row {
          display: flex;
          align-items: center;
          gap: 0.5rem;
          align-self: flex-end;

          .version-name-input {
            height: 36px;
            padding: 0.3rem 0.75rem;
            background: var(--bg-elevated);
            border: 1px solid var(--border-light);
            border-radius: 7px;
            color: var(--text-primary);
            font-size: 0.85rem;
            min-width: 160px;
            transition: border-color 0.18s;

            &::placeholder { color: var(--text-muted); }

            &:focus {
              outline: none;
              border-color: var(--accent);
            }
          }

          .btn { align-self: unset; }
        }

        // Tax section grouping
        .tax-section {
          width: 100%;
          padding: 0.75rem 0 0.25rem 0;

          .tax-section-header {
            font-size: 0.72rem;
            font-weight: 700;
            color: var(--accent);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .sia-tooltip {
              font-size: 0.85rem;
              cursor: help;
              opacity: 0.7;
              transition: opacity 0.18s;

              &:hover {
                opacity: 1;
              }
            }
          }

          .tax-section-fields {
            display: flex;
            flex-wrap: wrap;
            align-items: flex-end;
            gap: 1rem;
          }
        }

        .tax-section-separator {
          width: 100%;
          border-top: 1px dashed var(--border);
          margin: 0.25rem 0;
        }
      }

      // Default-version banner (top of params box)
      .params-default-banner {
        width: 100%;
        padding: 0.55rem 0.9rem;
        background: rgba(248, 155, 41, 0.07);
        border: 1px solid rgba(248, 155, 41, 0.22);
        border-left: 3px solid #f89b29;
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);

        strong { color: #f89b29; font-weight: 700; }
      }

      // Tab nav
      .projection-tab-nav {
        display: flex;
        gap: 0;
        align-items: center;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }

        // Right-aligned default version badge
        .default-version-badge {
          margin-left: auto;
          padding: 0.22rem 0.75rem;
          background: rgba(248, 155, 41, 0.10);
          border: 1px solid rgba(248, 155, 41, 0.28);
          border-radius: 999px;
          font-size: 0.76rem;
          color: #f89b29;
          white-space: nowrap;
          flex-shrink: 0;

          strong { color: #f89b29; font-weight: 700; }
        }
      }

      // Params-link hint bar (Graph & Table tabs)
      .params-link-hint {
        width: 100%;
        padding: 0.5rem 0.9rem;
        margin-bottom: 1rem;
        background: rgba(16, 185, 129, 0.06);
        border: 1px solid rgba(16, 185, 129, 0.14);
        border-left: 3px solid var(--accent);
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);
        box-sizing: border-box;

        strong { color: var(--text-primary); font-weight: 600; }
        em { font-style: normal; font-weight: 600; color: var(--accent); }

        // Version-specific variant (amber)
        &.params-link-hint--versioned {
          background: rgba(248, 155, 41, 0.06);
          border-color: rgba(248, 155, 41, 0.18);
          border-left-color: #f89b29;

          strong { color: #f89b29; }
          em     { color: var(--accent); }
        }
      }

      .tab-panel { /* intentionally bare */ }

      .projection-chart-wrapper {
        height: 380px;
        position: relative;
      }

      .projection-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Data table
      .projection-table-wrapper {
        overflow-x: auto;
        border-radius: 7px;
        border: 1px solid var(--border);

        .table-controls {
          display: flex;
          align-items: center;
          padding: 0.6rem 0.9rem;
          border-bottom: 1px solid var(--border);
          background: var(--bg-elevated);

          .show-sia-checkbox {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            font-size: 0.82rem;
            font-weight: 500;
            color: var(--text-secondary);
            cursor: pointer;

            input[type='checkbox'] {
              width: 16px;
              height: 16px;
              accent-color: #2ec4b6;
              cursor: pointer;
            }
          }
        }
      }

      .projection-table {
        // ...existing projection-table styles...
        width: 100%;
        border-collapse: collapse;
        font-size: 0.77rem;

        thead {
          background: var(--bg-elevated);
          border-bottom: 1px solid var(--border);

          th {
            padding: 0.65rem 0.9rem;
            text-align: left;
            font-weight: 600;
            color: var(--text-muted);
            white-space: nowrap;
            text-transform: uppercase;
            font-size: 0.68rem;
            letter-spacing: 0.06em;
          }
        }

        tbody tr {
          border-bottom: 1px solid var(--border);
          transition: background 0.15s;

          &:last-child { border-bottom: none; }
          &:hover { background: var(--bg-elevated); }
        }

        td {
          padding: 0.55rem 0.9rem;

          &.year-col {
            font-weight: 700;
            color: var(--accent);
          }

          &.value-col {
            font-family: 'Monaco', 'Courier New', monospace;
            text-align: right;
            color: var(--text-secondary);
          }

          &.buys-col { color: var(--accent-purple); }

          &.profit-col {
            font-weight: 600;
            &.positive { color: var(--positive); }
            &.negative { color: var(--negative); }
          }

          &.eoy-col {
            font-weight: 700;
            color: var(--text-primary);
          }

          &.inflation-col { color: #f89b29; }

          &.tax-col {
            position: relative;

            &.tax-due {
              color: var(--negative);
              font-weight: 600;
            }

            .exit-tax-badge {
              display: inline-block;
              margin-left: 0.3rem;
              padding: 0.1rem 0.3rem;
              background: var(--accent-purple);
              color: #fff;
              border-radius: 3px;
              font-size: 0.62rem;
              font-weight: 700;
              vertical-align: middle;
              cursor: help;
            }
          }

          &.after-tax-col {
            font-weight: 700;
            color: var(--accent-cyan);
          }

          &.after-tax-inflation-col {
            font-weight: 700;
            color: var(--text-secondary);
          }

          &.sia-col {
            font-weight: 600;
            color: #2ec4b6;
          }
        }

        .sia-col-header {
          color: #2ec4b6 !important;
          border-left: 2px solid rgba(46, 196, 182, 0.25);
        }
      }

      // ── Versions tab ──────────────────────────────────────────────────────
      .versions-panel {
        .versions-layout {
          display: flex;
          flex-direction: column;
          gap: 1.75rem;

          .versions-table-container {
            width: 100%;
            overflow-x: auto;

            .no-versions-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 1rem 0;
              font-size: 0.88rem;
            }

            .versions-table {
              width: 100%;
              border-collapse: collapse;
              font-size: 0.78rem;

              thead {
                background: var(--bg-elevated);
                border-bottom: 1px solid var(--border);

                th {
                  padding: 0.5rem 0.75rem;
                  text-align: left;
                  font-weight: 600;
                  color: var(--text-muted);
                  white-space: nowrap;
                  text-transform: uppercase;
                  font-size: 0.66rem;
                  letter-spacing: 0.06em;
                }
              }

              tbody tr {
                border-bottom: 1px solid var(--border);
                transition: background 0.15s;

                &:last-child { border-bottom: none; }
                &:hover { background: var(--bg-elevated); cursor: pointer; }

                &.version-selected td {
                  background: rgba(16, 185, 129, 0.08);
                }

                &.version-default td {
                  background: rgba(248, 155, 41, 0.05);
                }
              }

              td {
                padding: 0.45rem 0.75rem;
                color: var(--text-secondary);
                white-space: nowrap;

                &.version-check-col {
                  text-align: center;
                  width: 36px;

                  input[type='checkbox'] {
                    accent-color: var(--accent);
                    width: 14px;
                    height: 14px;
                    cursor: pointer;
                  }
                }

                &.version-num-col {
                  color: var(--text-primary);
                  font-size: 0.82rem;
                  display: flex;
                  align-items: center;
                  gap: 0.4rem;
                  flex-wrap: wrap;

                  .default-badge {
                    display: inline-flex;
                    align-items: center;
                    font-size: 0.68rem;
                    font-weight: 600;
                    color: #f89b29;
                    background: rgba(248, 155, 41, 0.12);
                    border: 1px solid rgba(248, 155, 41, 0.3);
                    border-radius: 999px;
                    padding: 0.1rem 0.45rem;
                    white-space: nowrap;
                  }
                }

                &.version-date-col {
                  font-size: 0.76rem;
                  color: var(--text-muted);
                }

                &.version-stat-col {
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.76rem;
                  text-align: right;
                }

                &.version-bool-col {
                  text-align: center;
                  font-weight: 700;
                  font-family: inherit;
                  color: var(--positive);
                }

                &.version-delete-col {
                  text-align: center;
                  width: 72px;
                  white-space: nowrap;
                }
              }

              .btn-set-default {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.5;
                margin-right: 0.15rem;

                &:hover:not(:disabled) {
                  background: rgba(248, 155, 41, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.3;
                }
              }

              .btn-delete-version {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.6;

                &:hover:not(:disabled) {
                  background: rgba(240, 82, 82, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.35;
                }
              }

              .delete-confirm-inline {
                display: flex;
                align-items: center;
                gap: 0.2rem;

                .btn-confirm-yes {
                  background: rgba(240, 82, 82, 0.2);
                  border: 1px solid rgba(240, 82, 82, 0.5);
                  color: #f05252;
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(240, 82, 82, 0.4); }
                  &:disabled { opacity: 0.4; cursor: not-allowed; }
                }

                .btn-confirm-no {
                  background: rgba(141, 160, 191, 0.1);
                  border: 1px solid rgba(141, 160, 191, 0.3);
                  color: var(--text-secondary);
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(141, 160, 191, 0.25); }
                }
              }
            }
          }

          .versions-chart-container {
            width: 100%;
            min-height: 540px;
            position: relative;

            canvas {
              width: 100% !important;
              height: 540px !important;
            }

            .versions-chart-hint {
              font-size: 0.8rem;
              color: var(--text-muted);
              margin-bottom: 0.85rem;
              padding: 0.45rem 0.75rem;
              background: var(--bg-surface);
              border-radius: 6px;
              border: 1px solid var(--border);
              display: inline-block;

              strong { color: var(--accent); }
            }

            .no-selection-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 4rem 1rem;
              text-align: center;
              font-size: 0.88rem;
            }
          }
        }
      }
    }

    .empty-state-card {
      @extend %card;
      padding: 1.5rem;
      text-align: center;
      background: linear-gradient(135deg, rgba(16, 185, 129, 0.06) 0%, rgba(5, 150, 105, 0.06) 100%);
      border-color: rgba(16, 185, 129, 0.22);

      .empty-state-title {
        margin: 0 0 0.35rem;
        font-size: 1.05rem;
        font-weight: 700;
        color: var(--text-primary);
      }

      .empty-state-text {
        margin: 0;
        font-size: 0.9rem;
        color: var(--text-secondary);
      }

      .btn {
        margin-top: 1rem;
        padding: 0.55rem 1.35rem;
        border: none;
        border-radius: 7px;
        font-size: 0.88rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.18s;

        &.btn-primary {
          background: var(--accent);
          color: #fff;

          &:hover {
            background: var(--accent-hover);
          }
        }
      }
    }

    // ── PORTFOLIO EVOLUTION SECTION ───────────────────────────────────────
    .evolution-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot  { background: var(--negative); border: 2px solid #c0392b; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      .evolution-period-nav {
        display: flex;
        gap: 0.5rem;
        flex-wrap: wrap;
        margin-bottom: 1rem;

        .period-btn {
          padding: 0.35rem 0.9rem;
          border-radius: 999px;
          border: 1px solid var(--border);
          background: transparent;
          color: var(--text-secondary);
          font-size: 0.82rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.18s;

          &:hover {
            border-color: var(--accent);
            color: var(--accent);
          }

          &.active {
            background: var(--accent);
            border-color: var(--accent);
            color: #fff;
            font-weight: 600;
          }
        }
      }

      .evolution-no-data {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }
    }

    // ── ALLOCATION SECTION ────────────────────────────────────────────────
    .allocation-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .allocation-content {
        @extend %card;
        display: flex;
        gap: 2.5rem;
        align-items: flex-start;
        padding: 1.75rem;

        .pie-wrapper {
          flex: 0 0 280px;
          height: 280px;
          position: relative;
        }

        .allocation-legend {
          flex: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
          gap: 0.75rem;
          align-content: start;

          .legend-item {
            display: flex;
            align-items: flex-start;
            gap: 0.65rem;
            padding: 0.75rem;
            border-radius: 8px;
            background: var(--bg-surface);
            border: 1px solid var(--border);
            transition: border-color 0.18s, box-shadow 0.18s;

            &:hover {
              border-color: var(--accent);
              box-shadow: 0 0 0 1px var(--accent-glow);
            }

            .legend-color {
              flex-shrink: 0;
              width: 13px;
              height: 13px;
              border-radius: 3px;
              margin-top: 4px;
            }

            .legend-details {
              display: flex;
              flex-direction: column;
              gap: 0.15rem;
              min-width: 0;

              .legend-ticker {
                font-weight: 700;
                font-size: 0.88rem;
                color: var(--accent);
              }

              .legend-name {
                font-size: 0.74rem;
                color: var(--text-muted);
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .legend-metrics {
                display: flex;
                align-items: center;
                gap: 0.4rem;
                margin-top: 0.2rem;

                .legend-amount {
                  font-weight: 600;
                  font-size: 0.88rem;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                .legend-percent {
                  font-size: 0.8rem;
                  color: var(--accent-purple);
                  font-weight: 600;
                  background: rgba(5, 150, 105, 0.12);
                  border-radius: 4px;
                  padding: 1px 6px;
                }
              }
            }
          }
        }
      }
    }

    // ── HOLDINGS SECTION ──────────────────────────────────────────────────
    .holdings-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .action-buttons {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        margin-bottom: 1.25rem;

        .readonly-notice {
          font-size: 0.85rem;
          color: #f89b29;
          padding: 0.45rem 0.9rem;
          background: rgba(248, 155, 41, 0.08);
          border: 1px solid rgba(248, 155, 41, 0.2);
          border-radius: 7px;
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }
      }

      // Tab nav (same pattern)
      .holdings-tab-nav {
        display: flex;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      // Evolution chart
      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot  { background: var(--negative); border: 2px solid #c0392b; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      // Period filter buttons
      .evolution-period-nav {
        display: flex;
        gap: 0.5rem;
        flex-wrap: wrap;
        margin-bottom: 1rem;

        .period-btn {
          padding: 0.35rem 0.9rem;
          border-radius: 999px;
          border: 1px solid var(--border);
          background: transparent;
          color: var(--text-secondary);
          font-size: 0.82rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.18s;

          &:hover {
            border-color: var(--accent);
            color: var(--accent);
          }

          &.active {
            background: var(--accent);
            border-color: var(--accent);
            color: #fff;
            font-weight: 600;
          }
        }
      }

      .evolution-no-data {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Holdings table
      .table-wrapper {
        overflow-x: auto;
        border-radius: var(--radius);
        border: 1px solid var(--border);
        background: var(--bg-card);

        .holdings-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.88rem;

          thead {
            background: var(--bg-elevated);
            border-bottom: 1px solid var(--border);

            th {
              padding: 0.85rem 1rem;
              text-align: left;
              font-weight: 600;
              color: var(--text-muted);
              white-space: nowrap;
              text-transform: uppercase;
              font-size: 0.68rem;
              letter-spacing: 0.06em;
              border-right: 1px solid var(--border);

              &:last-child { border-right: none; }
            }

            .periods-header th {
              border-bottom: 1px solid var(--border);
              padding: 0.45rem 1rem;
              font-size: 0.65rem;
            }
          }

          tbody {
            tr.holding-row {
              border-bottom: 1px solid var(--border);
              transition: background 0.15s;
              border-left: 3px solid transparent;

              &:hover { background: var(--bg-elevated); }

              &.price-unavailable {
                border-left-color: var(--negative);
                background: var(--negative-bg);
              }

              td {
                padding: 0.85rem 1rem;
                border-right: 1px solid var(--border);

                &:last-child { border-right: none; }

                &.ticker {
                  font-weight: 700;
                  color: var(--accent);
                  font-size: 0.95rem;
                }

                &.quantity, &.price {
                  text-align: right;
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.85rem;
                  color: var(--text-secondary);
                }


                &.total-value {
                  text-align: right;
                  font-weight: 700;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                &.positive {
                  color: var(--positive);
                  font-weight: 600;
                  background: var(--positive-bg);
                }

                &.negative {
                  color: var(--negative);
                  font-weight: 600;
                  background: var(--negative-bg);
                }

                .gain-loss {
                  display: flex;
                  flex-direction: column;
                  align-items: flex-end;
                  gap: 0.2rem;
                  font-variant-numeric: tabular-nums;

                  .percent {
                    font-size: 0.78rem;
                    opacity: 0.75;
                  }
                }

                &.actions {
                  text-align: center;

                  .btn-link {
                    background: none;
                    border: 1px solid var(--border-light);
                    color: var(--accent);
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;

                    &:hover {
                      background: var(--accent-glow);
                      border-color: var(--accent);
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

// ── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .dashboard-container {
    padding: 1rem;

    .dashboard-content {
      .dashboard-header h1 { font-size: 1.3rem; }

      .allocation-section .allocation-content {
        flex-direction: column;
        align-items: center;

        .pie-wrapper {
          flex: 0 0 220px;
          height: 220px;
          width: 220px;
        }

        .allocation-legend {
          grid-template-columns: 1fr 1fr;
          width: 100%;
        }
      }

      .holdings-section .table-wrapper {
        font-size: 0.8rem;

        .holdings-table {
          thead th { padding: 0.6rem 0.5rem; }
          tbody td { padding: 0.6rem 0.5rem; }
        }
      }
    }
  }
}

// ── Global button primitives (usable outside .dashboard-content nesting) ─────
.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.55rem 1.35rem;
  border: none;
  border-radius: 8px;
  font-size: 0.88rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.18s;
  letter-spacing: 0.02em;
  font-family: inherit;

  &.btn-primary {
    background: var(--accent, #10B981);
    color: #fff;
    box-shadow: 0 0 0 0 rgba(16, 185, 129, 0.35);

    &:hover:not(:disabled) {
      background: var(--accent-hover, #3a7de0);
      box-shadow: 0 0 0 4px rgba(16, 185, 129, 0.22);
      transform: translateY(-1px);
    }

    &:disabled { opacity: 0.45; cursor: not-allowed; transform: none; }
  }

  &.btn-secondary {
    background: transparent;
    border: 1px solid var(--accent, #10B981);
    color: var(--accent, #10B981);

    &:hover:not(:disabled) {
      background: rgba(16, 185, 129, 0.10);
      transform: translateY(-1px);
    }

    &:disabled { opacity: 0.45; cursor: not-allowed; transform: none; }
  }
}

// ── MY GOAL SECTION ──────────────────────────────────────────────────────────

.goal-section {
  padding: 1.5rem 0;

  h2 {
    font-size: 1.35rem;
    font-weight: 700;
    color: #FFFFFF;
    margin: 0 0 1.25rem;
  }
}

.goal-info-notice {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  padding: 0.75rem 1rem;
  margin-bottom: 1.25rem;
  background: rgba(248, 155, 41, 0.07);
  border: 1px solid rgba(248, 155, 41, 0.25);
  border-left: 3px solid #f89b29;
  border-radius: 8px;
  font-size: 0.85rem;
  color: #c9a96e;
  line-height: 1.5;

  strong { color: #f89b29; font-weight: 600; }
}

.goal-loading {
  color: var(--text-secondary);
  font-size: 0.95rem;
  padding: 1rem 0;
}

.goal-empty-state {
  background: rgba(255, 255, 255, 0.03);
  border: 1px dashed rgba(16, 185, 129, 0.25);
  border-radius: 12px;
  padding: 2.5rem 2rem;
  text-align: center;

  .goal-empty-title {
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--text-secondary);
    margin: 0 0 0.6rem;
  }

  .goal-empty-hint {
    font-size: 0.9rem;
    color: var(--text-secondary);
    margin: 0;
    strong { color: #10B981; }
  }
}

.goal-source-hint {
  font-size: 0.85rem;
  color: var(--text-secondary);
  margin: 0 0 1.25rem;
  strong { color: #10B981; }
}

// ── Goal inner tab bar ──────────────────────────────────────────────────────
.goal-sub-tabs {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1.25rem;
}

.goal-sub-tab-btn {
  padding: 0.45rem 1.25rem;
  border-radius: 20px;
  border: 1px solid rgba(16, 185, 129, 0.25);
  background: transparent;
  color: var(--text-secondary);
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s, color 0.15s, border-color 0.15s;
  font-family: inherit;

  &:hover:not(.active) {
    background: rgba(16, 185, 129, 0.08);
    color: var(--text-secondary);
    border-color: rgba(16, 185, 129, 0.4);
  }

  &.active {
    background: rgba(16, 185, 129, 0.15);
    border-color: rgba(16, 185, 129, 0.6);
    color: #10B981;
    font-weight: 600;
  }
}

.goal-monthly-notice {
  background: rgba(16, 185, 129, 0.05);
  border: 1px solid rgba(16, 185, 129, 0.18);
  border-radius: 10px;
  padding: 1.25rem 1.5rem;
  color: var(--text-secondary);
  font-size: 0.9rem;
  margin-bottom: 1.75rem;
  strong { color: #10B981; }
}

.goal-chart-wrapper {
  position: relative;
  height: 360px;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(16, 185, 129, 0.12);
  border-radius: 12px;
  padding: 1rem;
  margin-bottom: 1.75rem;

  canvas { width: 100% !important; height: 100% !important; }
}

.goal-table-wrapper {
  overflow-x: auto;
  border-radius: 10px;
  border: 1px solid rgba(16, 185, 129, 0.12);
  margin-bottom: 1.25rem;
}

.goal-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.9rem;

  thead tr {
    background: rgba(255, 255, 255, 0.04);

    th {
      padding: 0.7rem 1.1rem;
      text-align: left;
      font-weight: 600;
      color: var(--text-secondary);
      font-size: 0.8rem;
      text-transform: uppercase;
      letter-spacing: 0.04em;
      border-bottom: 1px solid rgba(16, 185, 129, 0.12);
    }
  }

  tbody tr {
    border-bottom: 1px solid rgba(16, 185, 129, 0.07);
    transition: background 0.15s;

    &:last-child { border-bottom: none; }
    &:hover { background: rgba(16, 185, 129, 0.05); }
  }

  .goal-year-col {
    padding: 0.6rem 1.1rem;
    font-weight: 700;
    color: var(--text-secondary);
    width: 6rem;
  }

  .goal-value-col {
    padding: 0.4rem 1.1rem;
  }
}

.goal-value-input {
  width: 14rem;
  padding: 0.45rem 0.75rem;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(16, 185, 129, 0.25);
  border-radius: 7px;
  color: #FFFFFF;
  font-size: 0.9rem;
  font-family: inherit;
  transition: border-color 0.15s, background 0.15s;

  &:focus {
    outline: none;
    border-color: rgba(16, 185, 129, 0.6);
    background: rgba(16, 185, 129, 0.08);
  }

  &::-webkit-inner-spin-button,
  &::-webkit-outer-spin-button { opacity: 0.4; }
}

.goal-save-row {
  display: flex;
  justify-content: flex-end;
  margin-top: 0.5rem;
}

// "Save as goal" button in the versions table
.btn-save-as-goal {
  background: transparent;
  border: none;
  cursor: pointer;
  font-size: 1rem;
  padding: 0.2rem 0.4rem;
  border-radius: 6px;
  transition: background 0.15s;
  line-height: 1;

  &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.15); }
  &:disabled { opacity: 0.4; cursor: not-allowed; }
}

/* ── Taxes column button ──────────────────────────────────── */
.taxes-cell { white-space: nowrap; }

.btn-taxes {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  color: var(--text-secondary);
  border-radius: 8px;
  padding: 0.3rem 0.75rem;
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: border-color 0.15s, background 0.15s;

  &:hover {
    border-color: var(--accent);
    background: rgba(16, 185, 129, 0.08);
    color: var(--accent);
  }

  &--pending {
    border-color: rgba(248, 155, 41, 0.5);
    background: rgba(248, 155, 41, 0.07);
    color: #f89b29;
    &:hover { background: rgba(248, 155, 41, 0.14); }
  }
}

.taxes-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: #f89b29;
  animation: pulse-dot 2s infinite;
  flex-shrink: 0;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50%       { opacity: 0.5; transform: scale(1.5); }
}

/* ── Tax Summary Section ─────────────────────────────────── */
.tax-summary-section {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.8rem 2rem;
  margin-top: 1.5rem;
}

.tax-summary-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 1rem;
  margin-bottom: 1.5rem;

  h2 { font-size: 1.15rem; font-weight: 800; color: var(--text-primary); margin: 0 0 0.3rem; }
}

.tax-summary-sub {
  font-size: 0.83rem;
  color: var(--text-muted);
  margin: 0;
}

.tax-summary-actions {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.btn-mark-all {
  background: rgba(16, 185, 129, 0.1);
  color: var(--positive);
  border: 1px solid rgba(16, 185, 129, 0.3);
  border-radius: 8px;
  padding: 0.45rem 1rem;
  font-size: 0.83rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s;
  &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.18); }
  &:disabled { opacity: 0.5; cursor: wait; }

  &--all {
    background: rgba(16, 185, 129, 0.1);
    color: var(--accent);
    border-color: rgba(16, 185, 129, 0.3);
    &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.18); }
  }
}

.tax-summary-loading {
  color: var(--text-muted);
  font-size: 0.88rem;
  padding: 1rem 0;
}

.tax-overview-cards {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
  margin-bottom: 1.8rem;
}

.tax-ov-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.8rem 1.3rem;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  min-width: 150px;

  &--pending { border-color: rgba(248, 155, 41, 0.4); background: rgba(248, 155, 41, 0.05); }
  &--year    { border-color: rgba(240, 82, 82, 0.35); background: rgba(240, 82, 82, 0.04); }
  &--paid    { border-color: rgba(16, 185, 129, 0.3); background: rgba(16, 185, 129, 0.04); }
}

.tax-ov-label {
  font-size: 0.72rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.tax-ov-value {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text-primary);
  &--green  { color: var(--positive); }
  &--accent { color: var(--accent); font-size: 0.9rem; }
}

.tax-empty {
  color: var(--text-secondary);
  font-size: 0.88rem;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 1.2rem 1.5rem;
}

/* Per-holding groups */
.tax-holding-group {
  margin-bottom: 1.4rem;

  &:last-child { margin-bottom: 0; }
}

.tax-holding-header {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.6rem 0.8rem;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-bottom: none;
  border-radius: 10px 10px 0 0;
  font-size: 0.88rem;

  strong { color: var(--text-primary); font-size: 0.95rem; }
}

.tax-holding-name { color: var(--text-muted); font-size: 0.82rem; }

.tax-holding-pending {
  margin-left: auto;
  font-size: 0.78rem;
  font-weight: 700;
  color: #f89b29;
  background: rgba(248, 155, 41, 0.1);
  border: 1px solid rgba(248, 155, 41, 0.3);
  border-radius: 6px;
  padding: 0.15rem 0.55rem;
}

.tax-events-table-wrap {
  overflow-x: auto;
  border: 1px solid var(--border);
  border-radius: 0 0 10px 10px;
}

.tax-events-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.83rem;

  th {
    padding: 0.5rem 0.9rem;
    background: var(--bg-card);
    color: var(--text-secondary);
    font-weight: 600;
    text-align: left;
    white-space: nowrap;
  }

  td {
    padding: 0.55rem 0.9rem;
    color: var(--text-primary);
    border-top: 1px solid var(--border);
    white-space: nowrap;
  }

  tr.tax-row-pending td { background: rgba(248, 155, 41, 0.025); }
  tr.tax-row-paid td    { opacity: 0.65; }
}

.te-type-badge {
  display: inline-block;
  border-radius: 5px;
  padding: 0.15rem 0.5rem;
  font-size: 0.74rem;
  font-weight: 600;

  &--disposal {
    background: rgba(16, 185, 129, 0.12);
    color: var(--accent);
    border: 1px solid rgba(16, 185, 129, 0.25);
  }
  &--sell {
    background: rgba(5, 150, 105, 0.12);
    color: var(--accent-purple);
    border: 1px solid rgba(5, 150, 105, 0.25);
  }
}

.gain-pos { color: var(--positive); }
.gain-neg { color: var(--negative); }
.te-tax-amt { font-weight: 700; color: var(--negative); }

.te-status {
  display: inline-block;
  border-radius: 5px;
  padding: 0.15rem 0.5rem;
  font-size: 0.73rem;
  font-weight: 700;

  &--pending {
    background: rgba(248, 155, 41, 0.12);
    color: #f89b29;
    border: 1px solid rgba(248, 155, 41, 0.3);
  }
  &--paid {
    background: rgba(16, 185, 129, 0.1);
    color: var(--positive);
    border: 1px solid rgba(16, 185, 129, 0.25);
  }
}

.btn-te-paid {
  background: rgba(16, 185, 129, 0.1);
  color: var(--positive);
  border: 1px solid rgba(16, 185, 129, 0.3);
  border-radius: 5px;
  padding: 0.2rem 0.6rem;
  font-size: 0.74rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s;
  &:hover { background: rgba(16, 185, 129, 0.2); }
}

// Tax-free allowance input hint
.param-hint {
  display: block;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 0.25rem;
}

// Tax-free allowance overview card
.tax-ov-card--allowance {
  background: rgba(16, 185, 129, 0.1);
  border: 1px solid rgba(16, 185, 129, 0.25);
}

// Tax-free allowance year breakdown
.tax-allowance-section {
  margin: 1rem 0 1.25rem;
  background: rgba(16, 185, 129, 0.06);
  border: 1px solid rgba(16, 185, 129, 0.18);
  border-radius: 10px;
  padding: 1rem 1.2rem;
}

.tax-allowance-header {
  font-size: 0.9rem;
  color: var(--text-secondary);
  margin-bottom: 0.75rem;
  strong { color: #10B981; }
}

.tax-allowance-rows {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-bottom: 0.75rem;
}

.tax-allowance-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 1.5rem;
  align-items: baseline;
  padding: 0.4rem 0.6rem;
  background: rgba(255, 255, 255, 0.03);
  border-radius: 6px;
  font-size: 0.84rem;
  color: var(--text-secondary);
  strong { color: var(--text-primary); }
}

.tax-allowance-year {
  font-weight: 700;
  color: var(--text-primary);
  min-width: 3rem;
}

.tax-allowance-deduct {
  color: #f89b29;
}

.tax-allowance-result strong {
  color: var(--positive);
}

.tax-allowance-total {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 0.6rem;
  border-top: 1px solid rgba(16, 185, 129, 0.2);
  font-size: 0.88rem;
  color: var(--text-secondary);
  strong {
    color: var(--positive);
    font-size: 1rem;
  }
}

// Top-level menu that splits dashboard into Portfolio and Projections views.
.main-menu-nav {
  display: flex;
  gap: 0.75rem;
  margin: 0 0 1.25rem;
  padding: 0.35rem;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(16, 185, 129, 0.18);
  border-radius: 12px;
}

.main-menu-btn {
  flex: 1;
  min-width: 0;
  border: 1px solid transparent;
  background: transparent;
  color: var(--text-secondary);
  font-weight: 700;
  font-size: 0.92rem;
  border-radius: 9px;
  padding: 0.65rem 0.9rem;
  cursor: pointer;
  transition: all 0.2s ease;

  &:hover {
    color: #FFFFFF;
    background: rgba(16, 185, 129, 0.1);
  }

  &.active {
    color: #FFFFFF;
    background: linear-gradient(135deg, rgba(16, 185, 129, 0.25) 0%, rgba(5, 150, 105, 0.22) 100%);
    border-color: rgba(16, 185, 129, 0.45);
    box-shadow: 0 0 0 1px rgba(16, 185, 129, 0.2) inset;
  }
}

@media (max-width: 768px) {
  .main-menu-nav {
    gap: 0.5rem;
    padding: 0.3rem;
  }

  .main-menu-btn {
    font-size: 0.85rem;
    padding: 0.55rem 0.65rem;
  }
}

// ── STICKY HEADER WRAPPER ────────────────────────────────────────────────────
// Wraps both the viewing-as banner and the nav so they stick together at top.
.sticky-header {
  position: sticky;
  top: 0;
  z-index: 1000;
  margin: -2rem -2.5rem 2rem -2.5rem;

  @media (max-width: 768px) {
    margin: -2rem -1rem 1.5rem -1rem;
  }
}

// ── VIEWING-AS BANNER ────────────────────────────────────────────────────────
.viewing-as-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.7rem 2.5rem;
  background: linear-gradient(135deg, rgba(16, 185, 129, 0.15) 0%, rgba(5, 150, 105, 0.15) 100%);
  border-bottom: 1px solid rgba(16, 185, 129, 0.3);

  .viewing-as-label {
    font-size: 0.9rem;
    color: var(--text-secondary);
    display: flex;
    align-items: center;
    gap: 0.6rem;

    strong { color: #10B981; }

    .readonly-chip {
      font-size: 0.75rem;
      padding: 0.15rem 0.55rem;
      background: rgba(248, 155, 41, 0.15);
      color: #f89b29;
      border-radius: 999px;
      border: 1px solid rgba(248, 155, 41, 0.3);
    }
  }

  .btn-stop-viewing {
    flex-shrink: 0;
    padding: 0.4rem 0.9rem;
    background: rgba(255, 255, 255, 0.07);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: 8px;
    color: var(--text-secondary);
    font-size: 0.83rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;

    &:hover {
      background: rgba(255, 255, 255, 0.12);
      color: #fff;
    }
  }

  @media (max-width: 768px) {
    padding: 0.6rem 1rem;
    flex-wrap: wrap;
  }
}

// ── TOP NAVIGATION ──────────────────────────────────────────────────────────
.top-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2.5rem;
  background: linear-gradient(135deg, #1E293B 0%, #1E293B 100%);
  border-bottom: 1px solid var(--border);
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.3);
  // sticky + margins moved to .sticky-header wrapper

  .nav-left {
    flex: 0 0 auto;

    .app-brand {
      font-size: 1.05rem;
      font-weight: 800;
      color: var(--text-primary);
      letter-spacing: -0.02em;
      display: flex;
      align-items: center;
      gap: 0.6rem;

      &__logo {
        height: 36px;
        width: auto;
        object-fit: contain;
        display: block;
      }

      &__text {
        display: flex;
        flex-direction: column;
        line-height: 1.05;
      }

      &__slogan {
        font-size: 0.68rem;
        font-weight: 600;
        color: var(--text-secondary);
        letter-spacing: 0.02em;
      }
    }
  }

  .nav-right {
    flex: 0 0 auto;

    .user-menu {
      display: flex;
      align-items: center;
      gap: 1.25rem;
      padding: 0.5rem 1rem 0.5rem 1.25rem;
      background: rgba(255, 255, 255, 0.03);
      border: 1px solid rgba(16, 185, 129, 0.1);
      border-radius: 12px;
      transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);

      &:hover {
        background: rgba(255, 255, 255, 0.06);
        border-color: rgba(16, 185, 129, 0.25);
        box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.08);
      }

      .user-info {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        min-width: 0;

        .avatar-wrapper {
          flex-shrink: 0;
          width: 40px;
          height: 40px;
          border-radius: 50%;
          background: var(--bg-elevated);
          border: 2px solid var(--border-light);
          overflow: hidden;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: all 0.2s;

          .avatar {
            width: 100%;
            height: 100%;
            object-fit: cover;
          }

          .avatar-placeholder {
            width: 100%;
            height: 100%;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 700;
            font-size: 1rem;
            background: linear-gradient(135deg, var(--accent-purple) 0%, var(--accent) 100%);
            color: #fff;
          }

          &:hover {
            border-color: var(--accent);
            box-shadow: 0 0 0 2px rgba(16, 185, 129, 0.2);
            transform: scale(1.05);
          }
        }

        .user-details {
          display: flex;
          flex-direction: column;
          gap: 0.15rem;
          min-width: 0;

          .user-name {
            font-weight: 600;
            font-size: 0.95rem;
            color: var(--text-primary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }

          .user-email {
            font-size: 0.78rem;
            color: var(--text-secondary);
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
          }
        }
      }

      .btn-share {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(5, 150, 105, 0.12);
        color: #a78bfa;
        border: 1px solid rgba(5, 150, 105, 0.25);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .share-text { display: inline; }

        &:hover {
          background: rgba(5, 150, 105, 0.22);
          border-color: rgba(5, 150, 105, 0.45);
          color: #c4b5fd;
          transform: translateY(-1px);
        }
      }

      .btn-settings {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.5rem 0.9rem;
        background: rgba(16, 185, 129, 0.10);
        color: #93c5fd;
        border: 1px solid rgba(16, 185, 129, 0.22);
        border-radius: 8px;
        font-size: 0.85rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .settings-text { display: inline; }

        &:hover {
          background: rgba(16, 185, 129, 0.22);
          border-color: rgba(16, 185, 129, 0.45);
          color: #bfdbfe;
          transform: translateY(-1px);
        }
      }

      .btn-logout {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.4rem;
        padding: 0.45rem 0.9rem;
        background: rgba(240, 82, 82, 0.08);
        color: #f05252;
        border: 1px solid rgba(240, 82, 82, 0.22);
        border-radius: 8px;
        font-size: 0.83rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.2s;
        white-space: nowrap;

        .logout-icon { font-size: 0.95rem; }
        .logout-text { display: inline; }

        &:hover {
          background: rgba(240, 82, 82, 0.18);
          border-color: rgba(240, 82, 82, 0.5);
          color: #ff6b6b;
          transform: translateY(-1px);
        }
      }

      // ── Irish Investor Toggle ──────────────────────────────────────────────
      .irish-investor-toggle {
        flex-shrink: 0;
        display: flex;
        align-items: center;
        gap: 0.45rem;
        padding: 0.4rem 0.75rem;
        background: rgba(255, 255, 255, 0.04);
        border: 1px solid rgba(255, 255, 255, 0.1);
        border-radius: 8px;
        cursor: pointer;
        transition: all 0.2s;
        user-select: none;

        .irish-toggle-label {
          font-size: 0.78rem;
          font-weight: 600;
          color: var(--text-secondary);
          white-space: nowrap;
          transition: color 0.2s;
        }

        .irish-toggle-track {
          position: relative;
          width: 30px;
          height: 16px;
          background: rgba(255, 255, 255, 0.1);
          border-radius: 16px;
          transition: background 0.2s;
          flex-shrink: 0;

          .irish-toggle-thumb {
            position: absolute;
            top: 2px;
            left: 2px;
            width: 12px;
            height: 12px;
            border-radius: 50%;
            background: #E5E7EB;
            transition: transform 0.2s, background 0.2s;
          }
        }

        &.active {
          background: rgba(16, 185, 129, 0.08);
          border-color: rgba(16, 185, 129, 0.3);

          .irish-toggle-label {
            color: #10B981;
          }

          .irish-toggle-track {
            background: rgba(16, 185, 129, 0.25);

            .irish-toggle-thumb {
              transform: translateX(14px);
              background: #10B981;
            }
          }
        }

        &:hover {
          background: rgba(16, 185, 129, 0.12);
          border-color: rgba(16, 185, 129, 0.4);
        }
      }
    }
  }

  @media (max-width: 768px) {
    padding: 0.8rem 1rem;
    flex-wrap: wrap;
    gap: 0.75rem;

    .nav-left .app-brand {
      font-size: 1.1rem;

      .app-brand__slogan {
        display: none;
      }
    }

    .nav-right .user-menu {
      gap: 0.75rem;
      padding: 0.4rem 0.8rem;

      .user-info .avatar-wrapper {
        width: 36px;
        height: 36px;
      }

      .user-details {
        display: none;
      }

      .btn-share .share-text {
        display: none;
      }

      .btn-settings .settings-text {
        display: none;
      }

      .btn-logout {
        padding: 0.4rem 0.8rem;
        font-size: 0.78rem;

        .logout-text {
          display: none;
        }
      }

      .irish-investor-toggle .irish-toggle-label {
        display: none;
      }
    }
  }
}

// ── Shared helpers ──────────────────────────────────────────────────────────
%card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-md);
}

%section-heading {
  font-size: 1.1rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  margin-bottom: 1.25rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;

  &::before {
    content: '';
    display: inline-block;
    width: 3px;
    height: 1em;
    border-radius: 2px;
    background: var(--accent);
  }
}

// ── Sortable table header ───────────────────────────────────────────────────
th.sortable {
  cursor: pointer;
  user-select: none;
  white-space: nowrap;

  &::after {
    content: ' ⇅';
    font-size: 0.7em;
    opacity: 0.35;
    transition: opacity 0.15s;
  }

  &:hover::after { opacity: 0.7; }

  &.sort-asc::after  { content: ' ▲'; opacity: 0.85; color: var(--accent); }
  &.sort-desc::after { content: ' ▼'; opacity: 0.85; color: var(--accent); }

  &:hover { color: var(--accent); }
}

// ── Dashboard shell ─────────────────────────────────────────────────────────
.dashboard-container {
  padding: 2rem 2.5rem;
  max-width: 1700px;
  margin: 0 auto;

  // Loading & error states
  .loading, .error {
    text-align: center;
    padding: 4rem 2rem;
    font-size: 1rem;
    color: var(--text-secondary);

    button {
      margin-top: 1.25rem;
      padding: 0.6rem 1.75rem;
      background: var(--accent);
      color: #fff;
      border: none;
      border-radius: 8px;
      cursor: pointer;
      font-weight: 600;
      transition: background 0.2s;

      &:hover { background: var(--accent-hover); }
    }
  }

  .error {
    @extend %card;
    color: var(--negative);
    border-color: rgba(240, 82, 82, 0.3);
    background: rgba(240, 82, 82, 0.06);
  }

  // ── Dashboard content ──────────────────────────────────────────────────────
  .dashboard-content {

    // ── HEADER ────────────────────────────────────────────────────────────────
    .dashboard-header {
      margin-bottom: 2.5rem;

      h1 {
        font-size: 1.65rem;
        font-weight: 800;
        letter-spacing: -0.03em;
        color: var(--text-primary);
        margin-bottom: 1.75rem;
        display: flex;
        align-items: center;
        gap: 0.75rem;

        &::after {
          content: '';
          flex: 1;
          height: 1px;
          background: var(--border);
        }
      }

      // Metric cards grid
      .metrics-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
        gap: 1rem;
        margin-bottom: 1.5rem;

        .metric-card {
          @extend %card;
          padding: 1.35rem 1.5rem;
          position: relative;
          overflow: hidden;
          transition: transform 0.18s, box-shadow 0.18s;

          &::before {
            content: '';
            position: absolute;
            top: 0; left: 0; right: 0;
            height: 2px;
            background: var(--border-light);
            transition: background 0.2s;
          }

          &:hover {
            transform: translateY(-3px);
            box-shadow: 0 8px 28px rgba(0,0,0,0.55);
            &::before { background: var(--accent); }
          }

          .metric-label {
            font-size: 0.72rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .exclamation-mark {
              display: inline-flex;
              align-items: center;
              justify-content: center;
              width: 1.15rem;
              height: 1.15rem;
              background: var(--negative);
              color: #fff;
              border-radius: 50%;
              font-size: 0.7rem;
              font-weight: 700;
              flex-shrink: 0;
            }
          }

          .metric-value {
            font-size: 1.65rem;
            font-weight: 800;
            letter-spacing: -0.03em;
            color: var(--text-primary);
            margin-bottom: 0.25rem;
            font-variant-numeric: tabular-nums;
          }

          .metric-percent {
            font-size: 0.9rem;
            font-weight: 600;
            color: var(--text-secondary);
          }

          .price-unavailable-message {
            font-size: 0.75rem;
            color: var(--negative);
            margin-top: 0.6rem;
            font-style: italic;
            background: var(--negative-bg);
            padding: 0.35rem 0.6rem;
            border-radius: 5px;
          }

          // Total Holdings – blue gradient hero card
          &.total {
            background: linear-gradient(135deg, #1a3a6e 0%, #0f224d 100%);
            border-color: rgba(16, 185, 129, 0.3);

            &::before { background: var(--accent); }

            .metric-label { color: rgba(228, 234, 245, 0.6); }
            .metric-value { color: #fff; font-size: 1.9rem; }
          }

          &.positive {
            .metric-value, .metric-percent { color: var(--positive); }
            &::before { background: var(--positive); }
          }

          &.negative {
            .metric-value, .metric-percent { color: var(--negative); }
            &::before { background: var(--negative); }
          }
        }
      }

      .action-buttons {
        display: flex;
        gap: 0.75rem;

        .btn {
          padding: 0.55rem 1.35rem;
          font-size: 0.88rem;
          border: none;
          border-radius: 8px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;
            box-shadow: 0 0 0 0 var(--accent-glow);

            &:hover {
              background: var(--accent-hover);
              box-shadow: 0 0 0 4px var(--accent-glow);
            }
          }
        }
      }
    }

    // ── PROJECTION SECTION ─────────────────────────────────────────────────
    .projection-section {
      @extend %card;
      padding: 1.75rem;
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      // Parameter inputs row
      .projection-params {
        display: flex;
        flex-wrap: wrap;
        align-items: flex-end;
        gap: 1rem;
        margin-bottom: 1.75rem;
        padding: 1.25rem;
        background: var(--bg-surface);
        border: 1px solid var(--border);
        border-radius: 8px;

        .param-group {
          display: flex;
          flex-direction: column;
          gap: 0.35rem;

          label {
            font-size: 0.68rem;
            font-weight: 600;
            color: var(--text-muted);
            text-transform: uppercase;
            letter-spacing: 0.07em;
          }

          input[type='number'] {
            width: 130px;
            padding: 0.5rem 0.7rem;
            border: 1px solid var(--border-light);
            border-radius: 7px;
            font-size: 0.9rem;
            color: var(--text-primary);
            background: var(--bg-input);
            transition: border-color 0.18s, box-shadow 0.18s;
            font-variant-numeric: tabular-nums;

            &:focus {
              outline: none;
              border-color: var(--accent);
              box-shadow: 0 0 0 3px var(--accent-glow);
            }
          }

          &.checkbox-group {
            justify-content: flex-end;

            .checkbox-label {
              display: flex;
              align-items: center;
              gap: 0.5rem;
              font-size: 0.82rem;
              font-weight: 500;
              color: var(--text-secondary);
              text-transform: none;
              letter-spacing: normal;
              cursor: pointer;
              white-space: nowrap;

              input[type='checkbox'] {
                width: 16px;
                height: 16px;
                accent-color: var(--accent);
                cursor: pointer;
              }
            }

            .setting-toggle {
              display: inline-flex;
              align-items: center;
              gap: 0.75rem;
              padding: 0.45rem 0.7rem;
              border: 1px solid var(--border-light);
              border-radius: 999px;
              background: rgba(255, 255, 255, 0.03);
              color: var(--text-secondary);
              cursor: pointer;
              transition: all 0.18s ease;

              .setting-toggle-label {
                font-size: 0.82rem;
                font-weight: 500;
                color: inherit;
                text-transform: none;
                letter-spacing: normal;
                white-space: nowrap;
              }

              .setting-toggle-track {
                position: relative;
                width: 34px;
                height: 18px;
                border-radius: 999px;
                background: rgba(255, 255, 255, 0.12);
                transition: background 0.18s ease;
                flex-shrink: 0;

                .setting-toggle-thumb {
                  position: absolute;
                  top: 2px;
                  left: 2px;
                  width: 14px;
                  height: 14px;
                  border-radius: 50%;
                  background: #E5E7EB;
                  transition: transform 0.18s ease, background 0.18s ease;
                }
              }

              &:hover {
                border-color: rgba(16, 185, 129, 0.45);
                background: rgba(16, 185, 129, 0.08);
                color: var(--text-primary);
              }

              &:focus-visible {
                outline: none;
                box-shadow: 0 0 0 3px var(--accent-glow);
                border-color: var(--accent);
              }

              &.active {
                border-color: rgba(16, 185, 129, 0.35);
                background: rgba(16, 185, 129, 0.08);
                color: var(--text-primary);

                .setting-toggle-track {
                  background: rgba(16, 185, 129, 0.24);

                  .setting-toggle-thumb {
                    transform: translateX(16px);
                    background: #10B981;
                  }
                }
              }
            }
          }

          &.start-amount-group {
            .start-amount-input-row {
              display: flex;
              align-items: center;
              gap: 0.4rem;

              input[type='number'] {
                width: 130px;
              }

              .btn-copy-portfolio {
                flex-shrink: 0;
                display: flex;
                align-items: center;
                justify-content: center;
                width: 32px;
                height: 32px;
                padding: 0;
                background: var(--bg-elevated);
                border: 1px solid var(--border-light);
                border-radius: 7px;
                font-size: 0.9rem;
                cursor: pointer;
                transition: all 0.18s;
                color: var(--text-secondary);

                &:hover {
                  background: rgba(16, 185, 129, 0.12);
                  border-color: var(--accent);
                  color: var(--accent);
                  transform: scale(1.1);
                }

                &:active {
                  transform: scale(0.96);
                }
              }
            }

            .start-amount-hint {
              font-size: 0.65rem;
              color: var(--text-muted);
              font-style: italic;
              margin-top: 0.15rem;
              display: block;
            }
          }
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }

          &.btn-secondary {
            background: transparent;
            border: 1px solid var(--accent);
            color: var(--accent);

            &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.10); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }

        .save-version-row {
          display: flex;
          align-items: center;
          gap: 0.5rem;
          align-self: flex-end;

          .version-name-input {
            height: 36px;
            padding: 0.3rem 0.75rem;
            background: var(--bg-elevated);
            border: 1px solid var(--border-light);
            border-radius: 7px;
            color: var(--text-primary);
            font-size: 0.85rem;
            min-width: 160px;
            transition: border-color 0.18s;

            &::placeholder { color: var(--text-muted); }

            &:focus {
              outline: none;
              border-color: var(--accent);
            }
          }

          .btn { align-self: unset; }
        }

        // Tax section grouping
        .tax-section {
          width: 100%;
          padding: 0.75rem 0 0.25rem 0;

          .tax-section-header {
            font-size: 0.72rem;
            font-weight: 700;
            color: var(--accent);
            text-transform: uppercase;
            letter-spacing: 0.08em;
            margin-bottom: 0.65rem;
            display: flex;
            align-items: center;
            gap: 0.4rem;

            .sia-tooltip {
              font-size: 0.85rem;
              cursor: help;
              opacity: 0.7;
              transition: opacity 0.18s;

              &:hover {
                opacity: 1;
              }
            }
          }

          .tax-section-fields {
            display: flex;
            flex-wrap: wrap;
            align-items: flex-end;
            gap: 1rem;
          }
        }

        .tax-section-separator {
          width: 100%;
          border-top: 1px dashed var(--border);
          margin: 0.25rem 0;
        }
      }

      // Default-version banner (top of params box)
      .params-default-banner {
        width: 100%;
        padding: 0.55rem 0.9rem;
        background: rgba(248, 155, 41, 0.07);
        border: 1px solid rgba(248, 155, 41, 0.22);
        border-left: 3px solid #f89b29;
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);

        strong { color: #f89b29; font-weight: 700; }
      }

      // Tab nav
      .projection-tab-nav {
        display: flex;
        gap: 0;
        align-items: center;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }

        // Right-aligned default version badge
        .default-version-badge {
          margin-left: auto;
          padding: 0.22rem 0.75rem;
          background: rgba(248, 155, 41, 0.10);
          border: 1px solid rgba(248, 155, 41, 0.28);
          border-radius: 999px;
          font-size: 0.76rem;
          color: #f89b29;
          white-space: nowrap;
          flex-shrink: 0;

          strong { color: #f89b29; font-weight: 700; }
        }
      }

      // Params-link hint bar (Graph & Table tabs)
      .params-link-hint {
        width: 100%;
        padding: 0.5rem 0.9rem;
        margin-bottom: 1rem;
        background: rgba(16, 185, 129, 0.06);
        border: 1px solid rgba(16, 185, 129, 0.14);
        border-left: 3px solid var(--accent);
        border-radius: 6px;
        font-size: 0.82rem;
        color: var(--text-secondary);
        box-sizing: border-box;

        strong { color: var(--text-primary); font-weight: 600; }
        em { font-style: normal; font-weight: 600; color: var(--accent); }

        // Version-specific variant (amber)
        &.params-link-hint--versioned {
          background: rgba(248, 155, 41, 0.06);
          border-color: rgba(248, 155, 41, 0.18);
          border-left-color: #f89b29;

          strong { color: #f89b29; }
          em     { color: var(--accent); }
        }
      }

      .tab-panel { /* intentionally bare */ }

      .projection-chart-wrapper {
        height: 380px;
        position: relative;
      }

      .projection-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Data table
      .projection-table-wrapper {
        overflow-x: auto;
        border-radius: 7px;
        border: 1px solid var(--border);

        .table-controls {
          display: flex;
          align-items: center;
          padding: 0.6rem 0.9rem;
          border-bottom: 1px solid var(--border);
          background: var(--bg-elevated);

          .show-sia-checkbox {
            display: flex;
            align-items: center;
            gap: 0.5rem;
            font-size: 0.82rem;
            font-weight: 500;
            color: var(--text-secondary);
            cursor: pointer;

            input[type='checkbox'] {
              width: 16px;
              height: 16px;
              accent-color: #2ec4b6;
              cursor: pointer;
            }
          }
        }
      }

      .projection-table {
        // ...existing projection-table styles...
        width: 100%;
        border-collapse: collapse;
        font-size: 0.77rem;

        thead {
          background: var(--bg-elevated);
          border-bottom: 1px solid var(--border);

          th {
            padding: 0.65rem 0.9rem;
            text-align: left;
            font-weight: 600;
            color: var(--text-muted);
            white-space: nowrap;
            text-transform: uppercase;
            font-size: 0.68rem;
            letter-spacing: 0.06em;
          }
        }

        tbody tr {
          border-bottom: 1px solid var(--border);
          transition: background 0.15s;

          &:last-child { border-bottom: none; }
          &:hover { background: var(--bg-elevated); }
        }

        td {
          padding: 0.55rem 0.9rem;

          &.year-col {
            font-weight: 700;
            color: var(--accent);
          }

          &.value-col {
            font-family: 'Monaco', 'Courier New', monospace;
            text-align: right;
            color: var(--text-secondary);
          }

          &.buys-col { color: var(--accent-purple); }

          &.profit-col {
            font-weight: 600;
            &.positive { color: var(--positive); }
            &.negative { color: var(--negative); }
          }

          &.eoy-col {
            font-weight: 700;
            color: var(--text-primary);
          }

          &.inflation-col { color: #f89b29; }

          &.tax-col {
            position: relative;

            &.tax-due {
              color: var(--negative);
              font-weight: 600;
            }

            .exit-tax-badge {
              display: inline-block;
              margin-left: 0.3rem;
              padding: 0.1rem 0.3rem;
              background: var(--accent-purple);
              color: #fff;
              border-radius: 3px;
              font-size: 0.62rem;
              font-weight: 700;
              vertical-align: middle;
              cursor: help;
            }
          }

          &.after-tax-col {
            font-weight: 700;
            color: var(--accent-cyan);
          }

          &.after-tax-inflation-col {
            font-weight: 700;
            color: var(--text-secondary);
          }

          &.sia-col {
            font-weight: 600;
            color: #2ec4b6;
          }
        }

        .sia-col-header {
          color: #2ec4b6 !important;
          border-left: 2px solid rgba(46, 196, 182, 0.25);
        }
      }

      // ── Versions tab ──────────────────────────────────────────────────────
      .versions-panel {
        .versions-layout {
          display: flex;
          flex-direction: column;
          gap: 1.75rem;

          .versions-table-container {
            width: 100%;
            overflow-x: auto;

            .no-versions-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 1rem 0;
              font-size: 0.88rem;
            }

            .versions-table {
              width: 100%;
              border-collapse: collapse;
              font-size: 0.78rem;

              thead {
                background: var(--bg-elevated);
                border-bottom: 1px solid var(--border);

                th {
                  padding: 0.5rem 0.75rem;
                  text-align: left;
                  font-weight: 600;
                  color: var(--text-muted);
                  white-space: nowrap;
                  text-transform: uppercase;
                  font-size: 0.66rem;
                  letter-spacing: 0.06em;
                }
              }

              tbody tr {
                border-bottom: 1px solid var(--border);
                transition: background 0.15s;

                &:last-child { border-bottom: none; }
                &:hover { background: var(--bg-elevated); cursor: pointer; }

                &.version-selected td {
                  background: rgba(16, 185, 129, 0.08);
                }

                &.version-default td {
                  background: rgba(248, 155, 41, 0.05);
                }
              }

              td {
                padding: 0.45rem 0.75rem;
                color: var(--text-secondary);
                white-space: nowrap;

                &.version-check-col {
                  text-align: center;
                  width: 36px;

                  input[type='checkbox'] {
                    accent-color: var(--accent);
                    width: 14px;
                    height: 14px;
                    cursor: pointer;
                  }
                }

                &.version-num-col {
                  color: var(--text-primary);
                  font-size: 0.82rem;
                  display: flex;
                  align-items: center;
                  gap: 0.4rem;
                  flex-wrap: wrap;

                  .default-badge {
                    display: inline-flex;
                    align-items: center;
                    font-size: 0.68rem;
                    font-weight: 600;
                    color: #f89b29;
                    background: rgba(248, 155, 41, 0.12);
                    border: 1px solid rgba(248, 155, 41, 0.3);
                    border-radius: 999px;
                    padding: 0.1rem 0.45rem;
                    white-space: nowrap;
                  }
                }

                &.version-date-col {
                  font-size: 0.76rem;
                  color: var(--text-muted);
                }

                &.version-stat-col {
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.76rem;
                  text-align: right;
                }

                &.version-bool-col {
                  text-align: center;
                  font-weight: 700;
                  font-family: inherit;
                  color: var(--positive);
                }

                &.version-delete-col {
                  text-align: center;
                  width: 72px;
                  white-space: nowrap;
                }
              }

              .btn-set-default {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.5;
                margin-right: 0.15rem;

                &:hover:not(:disabled) {
                  background: rgba(248, 155, 41, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.3;
                }
              }

              .btn-delete-version {
                background: none;
                border: none;
                cursor: pointer;
                padding: 0.2rem 0.35rem;
                border-radius: 4px;
                font-size: 0.9rem;
                line-height: 1;
                transition: background 0.15s, opacity 0.15s;
                opacity: 0.6;

                &:hover:not(:disabled) {
                  background: rgba(240, 82, 82, 0.15);
                  opacity: 1;
                }

                &:disabled {
                  cursor: not-allowed;
                  opacity: 0.35;
                }
              }

              .delete-confirm-inline {
                display: flex;
                align-items: center;
                gap: 0.2rem;

                .btn-confirm-yes {
                  background: rgba(240, 82, 82, 0.2);
                  border: 1px solid rgba(240, 82, 82, 0.5);
                  color: #f05252;
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(240, 82, 82, 0.4); }
                  &:disabled { opacity: 0.4; cursor: not-allowed; }
                }

                .btn-confirm-no {
                  background: rgba(141, 160, 191, 0.1);
                  border: 1px solid rgba(141, 160, 191, 0.3);
                  color: var(--text-secondary);
                  border-radius: 4px;
                  padding: 0.1rem 0.4rem;
                  font-size: 0.75rem;
                  cursor: pointer;
                  transition: background 0.15s;
                  &:hover { background: rgba(141, 160, 191, 0.25); }
                }
              }
            }
          }

          .versions-chart-container {
            width: 100%;
            min-height: 540px;
            position: relative;

            canvas {
              width: 100% !important;
              height: 540px !important;
            }

            .versions-chart-hint {
              font-size: 0.8rem;
              color: var(--text-muted);
              margin-bottom: 0.85rem;
              padding: 0.45rem 0.75rem;
              background: var(--bg-surface);
              border-radius: 6px;
              border: 1px solid var(--border);
              display: inline-block;

              strong { color: var(--accent); }
            }

            .no-selection-msg {
              color: var(--text-muted);
              font-style: italic;
              padding: 4rem 1rem;
              text-align: center;
              font-size: 0.88rem;
            }
          }
        }
      }
    }

    .empty-state-card {
      @extend %card;
      padding: 1.5rem;
      text-align: center;
      background: linear-gradient(135deg, rgba(16, 185, 129, 0.06) 0%, rgba(5, 150, 105, 0.06) 100%);
      border-color: rgba(16, 185, 129, 0.22);

      .empty-state-title {
        margin: 0 0 0.35rem;
        font-size: 1.05rem;
        font-weight: 700;
        color: var(--text-primary);
      }

      .empty-state-text {
        margin: 0;
        font-size: 0.9rem;
        color: var(--text-secondary);
      }

      .btn {
        margin-top: 1rem;
        padding: 0.55rem 1.35rem;
        border: none;
        border-radius: 7px;
        font-size: 0.88rem;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.18s;

        &.btn-primary {
          background: var(--accent);
          color: #fff;

          &:hover {
            background: var(--accent-hover);
          }
        }
      }
    }

    // ── PORTFOLIO EVOLUTION SECTION ───────────────────────────────────────
    .evolution-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot  { background: var(--negative); border: 2px solid #c0392b; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      .evolution-period-nav {
        display: flex;
        gap: 0.5rem;
        flex-wrap: wrap;
        margin-bottom: 1rem;

        .period-btn {
          padding: 0.35rem 0.9rem;
          border-radius: 999px;
          border: 1px solid var(--border);
          background: transparent;
          color: var(--text-secondary);
          font-size: 0.82rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.18s;

          &:hover {
            border-color: var(--accent);
            color: var(--accent);
          }

          &.active {
            background: var(--accent);
            border-color: var(--accent);
            color: #fff;
            font-weight: 600;
          }
        }
      }

      .evolution-no-data {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }
    }

    // ── ALLOCATION SECTION ────────────────────────────────────────────────
    .allocation-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .allocation-content {
        @extend %card;
        display: flex;
        gap: 2.5rem;
        align-items: flex-start;
        padding: 1.75rem;

        .pie-wrapper {
          flex: 0 0 280px;
          height: 280px;
          position: relative;
        }

        .allocation-legend {
          flex: 1;
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(210px, 1fr));
          gap: 0.75rem;
          align-content: start;

          .legend-item {
            display: flex;
            align-items: flex-start;
            gap: 0.65rem;
            padding: 0.75rem;
            border-radius: 8px;
            background: var(--bg-surface);
            border: 1px solid var(--border);
            transition: border-color 0.18s, box-shadow 0.18s;

            &:hover {
              border-color: var(--accent);
              box-shadow: 0 0 0 1px var(--accent-glow);
            }

            .legend-color {
              flex-shrink: 0;
              width: 13px;
              height: 13px;
              border-radius: 3px;
              margin-top: 4px;
            }

            .legend-details {
              display: flex;
              flex-direction: column;
              gap: 0.15rem;
              min-width: 0;

              .legend-ticker {
                font-weight: 700;
                font-size: 0.88rem;
                color: var(--accent);
              }

              .legend-name {
                font-size: 0.74rem;
                color: var(--text-muted);
                white-space: nowrap;
                overflow: hidden;
                text-overflow: ellipsis;
              }

              .legend-metrics {
                display: flex;
                align-items: center;
                gap: 0.4rem;
                margin-top: 0.2rem;

                .legend-amount {
                  font-weight: 600;
                  font-size: 0.88rem;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                .legend-percent {
                  font-size: 0.8rem;
                  color: var(--accent-purple);
                  font-weight: 600;
                  background: rgba(5, 150, 105, 0.12);
                  border-radius: 4px;
                  padding: 1px 6px;
                }
              }
            }
          }
        }
      }
    }

    // ── HOLDINGS SECTION ──────────────────────────────────────────────────
    .holdings-section {
      margin-bottom: 2rem;

      h2 {
        @extend %section-heading;
      }

      .action-buttons {
        display: flex;
        align-items: center;
        gap: 0.75rem;
        margin-bottom: 1.25rem;

        .readonly-notice {
          font-size: 0.85rem;
          color: #f89b29;
          padding: 0.45rem 0.9rem;
          background: rgba(248, 155, 41, 0.08);
          border: 1px solid rgba(248, 155, 41, 0.2);
          border-radius: 7px;
        }

        .btn {
          align-self: flex-end;
          padding: 0.55rem 1.35rem;
          border: none;
          border-radius: 7px;
          font-size: 0.88rem;
          font-weight: 600;
          cursor: pointer;
          transition: all 0.18s;
          letter-spacing: 0.02em;

          &.btn-primary {
            background: var(--accent);
            color: #fff;

            &:hover:not(:disabled) { background: var(--accent-hover); }
            &:disabled { opacity: 0.45; cursor: not-allowed; }
          }
        }
      }

      // Tab nav (same pattern)
      .holdings-tab-nav {
        display: flex;
        border-bottom: 1px solid var(--border);
        margin-bottom: 1.5rem;

        .tab-btn {
          padding: 0.55rem 1.25rem;
          border: none;
          background: none;
          font-size: 0.88rem;
          font-weight: 600;
          color: var(--text-muted);
          cursor: pointer;
          border-bottom: 2px solid transparent;
          margin-bottom: -1px;
          transition: color 0.18s, border-color 0.18s;

          &:hover { color: var(--accent); }

          &.active {
            color: var(--accent);
            border-bottom-color: var(--accent);
          }
        }
      }

      // Evolution chart
      .evolution-chart-wrapper {
        height: 400px;
        position: relative;
        @extend %card;
        padding: 1.25rem;
      }

      .evolution-loading {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      .evolution-legend {
        display: flex;
        align-items: center;
        gap: 0.5rem;
        margin-top: 0.75rem;
        padding: 0 0.25rem;
        font-size: 0.82rem;
        color: var(--text-secondary);

        .legend-dot {
          display: inline-block;
          width: 11px;
          height: 11px;
          border-radius: 50%;
          flex-shrink: 0;

          &.buy-dot  { background: var(--negative); border: 2px solid #c0392b; }
          &.value-dot { background: var(--accent); margin-left: 1rem; }
        }

        .legend-label { margin-right: 0.5rem; }
      }

      // Period filter buttons
      .evolution-period-nav {
        display: flex;
        gap: 0.5rem;
        flex-wrap: wrap;
        margin-bottom: 1rem;

        .period-btn {
          padding: 0.35rem 0.9rem;
          border-radius: 999px;
          border: 1px solid var(--border);
          background: transparent;
          color: var(--text-secondary);
          font-size: 0.82rem;
          font-weight: 500;
          cursor: pointer;
          transition: all 0.18s;

          &:hover {
            border-color: var(--accent);
            color: var(--accent);
          }

          &.active {
            background: var(--accent);
            border-color: var(--accent);
            color: #fff;
            font-weight: 600;
          }
        }
      }

      .evolution-no-data {
        text-align: center;
        padding: 2rem;
        color: var(--text-muted);
        font-size: 0.9rem;
      }

      // Holdings table
      .table-wrapper {
        overflow-x: auto;
        border-radius: var(--radius);
        border: 1px solid var(--border);
        background: var(--bg-card);

        .holdings-table {
          width: 100%;
          border-collapse: collapse;
          font-size: 0.88rem;

          thead {
            background: var(--bg-elevated);
            border-bottom: 1px solid var(--border);

            th {
              padding: 0.85rem 1rem;
              text-align: left;
              font-weight: 600;
              color: var(--text-muted);
              white-space: nowrap;
              text-transform: uppercase;
              font-size: 0.68rem;
              letter-spacing: 0.06em;
              border-right: 1px solid var(--border);

              &:last-child { border-right: none; }
            }

            .periods-header th {
              border-bottom: 1px solid var(--border);
              padding: 0.45rem 1rem;
              font-size: 0.65rem;
            }
          }

          tbody {
            tr.holding-row {
              border-bottom: 1px solid var(--border);
              transition: background 0.15s;
              border-left: 3px solid transparent;

              &:hover { background: var(--bg-elevated); }

              &.price-unavailable {
                border-left-color: var(--negative);
                background: var(--negative-bg);
              }

              td {
                padding: 0.85rem 1rem;
                border-right: 1px solid var(--border);

                &:last-child { border-right: none; }

                &.ticker {
                  font-weight: 700;
                  color: var(--accent);
                  font-size: 0.95rem;
                }

                &.quantity, &.price {
                  text-align: right;
                  font-family: 'Monaco', 'Courier New', monospace;
                  font-size: 0.85rem;
                  color: var(--text-secondary);
                }


                &.total-value {
                  text-align: right;
                  font-weight: 700;
                  color: var(--text-primary);
                  font-variant-numeric: tabular-nums;
                }

                &.positive {
                  color: var(--positive);
                  font-weight: 600;
                  background: var(--positive-bg);
                }

                &.negative {
                  color: var(--negative);
                  font-weight: 600;
                  background: var(--negative-bg);
                }

                .gain-loss {
                  display: flex;
                  flex-direction: column;
                  align-items: flex-end;
                  gap: 0.2rem;
                  font-variant-numeric: tabular-nums;

                  .percent {
                    font-size: 0.78rem;
                    opacity: 0.75;
                  }
                }

                &.actions {
                  text-align: center;

                  .btn-link {
                    background: none;
                    border: 1px solid var(--border-light);
                    color: var(--accent);
                    cursor: pointer;
                    font-weight: 600;
                    font-size: 0.8rem;
                    padding: 0.3rem 0.7rem;
                    border-radius: 6px;
                    transition: all 0.15s;

                    &:hover {
                      background: var(--accent-glow);
                      border-color: var(--accent);
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

// ── Responsive ───────────────────────────────────────────────────────────────
@media (max-width: 768px) {
  .dashboard-container {
    padding: 1rem;

    .dashboard-content {
      .dashboard-header h1 { font-size: 1.3rem; }

      .allocation-section .allocation-content {
        flex-direction: column;
        align-items: center;

        .pie-wrapper {
          flex: 0 0 220px;
          height: 220px;
          width: 220px;
        }

        .allocation-legend {
          grid-template-columns: 1fr 1fr;
          width: 100%;
        }
      }

      .holdings-section .table-wrapper {
        font-size: 0.8rem;

        .holdings-table {
          thead th { padding: 0.6rem 0.5rem; }
          tbody td { padding: 0.6rem 0.5rem; }
        }
      }
    }
  }
}

// ── Global button primitives (usable outside .dashboard-content nesting) ─────
.btn {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.55rem 1.35rem;
  border: none;
  border-radius: 8px;
  font-size: 0.88rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.18s;
  letter-spacing: 0.02em;
  font-family: inherit;

  &.btn-primary {
    background: var(--accent, #10B981);
    color: #fff;
    box-shadow: 0 0 0 0 rgba(16, 185, 129, 0.35);

    &:hover:not(:disabled) {
      background: var(--accent-hover, #3a7de0);
      box-shadow: 0 0 0 4px rgba(16, 185, 129, 0.22);
      transform: translateY(-1px);
    }

    &:disabled { opacity: 0.45; cursor: not-allowed; transform: none; }
  }

  &.btn-secondary {
    background: transparent;
    border: 1px solid var(--accent, #10B981);
    color: var(--accent, #10B981);

    &:hover:not(:disabled) {
      background: rgba(16, 185, 129, 0.10);
      transform: translateY(-1px);
    }

    &:disabled { opacity: 0.45; cursor: not-allowed; transform: none; }
  }
}

// ── MY GOAL SECTION ──────────────────────────────────────────────────────────

.goal-section {
  padding: 1.5rem 0;

  h2 {
    font-size: 1.35rem;
    font-weight: 700;
    color: #FFFFFF;
    margin: 0 0 1.25rem;
  }
}

.goal-info-notice {
  display: flex;
  align-items: flex-start;
  gap: 0.5rem;
  padding: 0.75rem 1rem;
  margin-bottom: 1.25rem;
  background: rgba(248, 155, 41, 0.07);
  border: 1px solid rgba(248, 155, 41, 0.25);
  border-left: 3px solid #f89b29;
  border-radius: 8px;
  font-size: 0.85rem;
  color: #c9a96e;
  line-height: 1.5;

  strong { color: #f89b29; font-weight: 600; }
}

.goal-loading {
  color: var(--text-secondary);
  font-size: 0.95rem;
  padding: 1rem 0;
}

.goal-empty-state {
  background: rgba(255, 255, 255, 0.03);
  border: 1px dashed rgba(16, 185, 129, 0.25);
  border-radius: 12px;
  padding: 2.5rem 2rem;
  text-align: center;

  .goal-empty-title {
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--text-secondary);
    margin: 0 0 0.6rem;
  }

  .goal-empty-hint {
    font-size: 0.9rem;
    color: var(--text-secondary);
    margin: 0;
    strong { color: #10B981; }
  }
}

.goal-source-hint {
  font-size: 0.85rem;
  color: var(--text-secondary);
  margin: 0 0 1.25rem;
  strong { color: #10B981; }
}

// ── Goal inner tab bar ──────────────────────────────────────────────────────
.goal-sub-tabs {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1.25rem;
}

.goal-sub-tab-btn {
  padding: 0.45rem 1.25rem;
  border-radius: 20px;
  border: 1px solid rgba(16, 185, 129, 0.25);
  background: transparent;
  color: var(--text-secondary);
  font-size: 0.875rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s, color 0.15s, border-color 0.15s;
  font-family: inherit;

  &:hover:not(.active) {
    background: rgba(16, 185, 129, 0.08);
    color: var(--text-secondary);
    border-color: rgba(16, 185, 129, 0.4);
  }

  &.active {
    background: rgba(16, 185, 129, 0.15);
    border-color: rgba(16, 185, 129, 0.6);
    color: #10B981;
    font-weight: 600;
  }
}

.goal-monthly-notice {
  background: rgba(16, 185, 129, 0.05);
  border: 1px solid rgba(16, 185, 129, 0.18);
  border-radius: 10px;
  padding: 1.25rem 1.5rem;
  color: var(--text-secondary);
  font-size: 0.9rem;
  margin-bottom: 1.75rem;
  strong { color: #10B981; }
}

.goal-chart-wrapper {
  position: relative;
  height: 360px;
  background: rgba(255, 255, 255, 0.02);
  border: 1px solid rgba(16, 185, 129, 0.12);
  border-radius: 12px;
  padding: 1rem;
  margin-bottom: 1.75rem;

  canvas { width: 100% !important; height: 100% !important; }
}

.goal-table-wrapper {
  overflow-x: auto;
  border-radius: 10px;
  border: 1px solid rgba(16, 185, 129, 0.12);
  margin-bottom: 1.25rem;
}

.goal-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.9rem;

  thead tr {
    background: rgba(255, 255, 255, 0.04);

    th {
      padding: 0.7rem 1.1rem;
      text-align: left;
      font-weight: 600;
      color: var(--text-secondary);
      font-size: 0.8rem;
      text-transform: uppercase;
      letter-spacing: 0.04em;
      border-bottom: 1px solid rgba(16, 185, 129, 0.12);
    }
  }

  tbody tr {
    border-bottom: 1px solid rgba(16, 185, 129, 0.07);
    transition: background 0.15s;

    &:last-child { border-bottom: none; }
    &:hover { background: rgba(16, 185, 129, 0.05); }
  }

  .goal-year-col {
    padding: 0.6rem 1.1rem;
    font-weight: 700;
    color: var(--text-secondary);
    width: 6rem;
  }

  .goal-value-col {
    padding: 0.4rem 1.1rem;
  }
}

.goal-value-input {
  width: 14rem;
  padding: 0.45rem 0.75rem;
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(16, 185, 129, 0.25);
  border-radius: 7px;
  color: #FFFFFF;
  font-size: 0.9rem;
  font-family: inherit;
  transition: border-color 0.15s, background 0.15s;

  &:focus {
    outline: none;
    border-color: rgba(16, 185, 129, 0.6);
    background: rgba(16, 185, 129, 0.08);
  }

  &::-webkit-inner-spin-button,
  &::-webkit-outer-spin-button { opacity: 0.4; }
}

.goal-save-row {
  display: flex;
  justify-content: flex-end;
  margin-top: 0.5rem;
}

// "Save as goal" button in the versions table
.btn-save-as-goal {
  background: transparent;
  border: none;
  cursor: pointer;
  font-size: 1rem;
  padding: 0.2rem 0.4rem;
  border-radius: 6px;
  transition: background 0.15s;
  line-height: 1;

  &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.15); }
  &:disabled { opacity: 0.4; cursor: not-allowed; }
}

/* ── Taxes column button ──────────────────────────────────── */
.taxes-cell { white-space: nowrap; }

.btn-taxes {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  color: var(--text-secondary);
  border-radius: 8px;
  padding: 0.3rem 0.75rem;
  font-size: 0.82rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: border-color 0.15s, background 0.15s;

  &:hover {
    border-color: var(--accent);
    background: rgba(16, 185, 129, 0.08);
    color: var(--accent);
  }

  &--pending {
    border-color: rgba(248, 155, 41, 0.5);
    background: rgba(248, 155, 41, 0.07);
    color: #f89b29;
    &:hover { background: rgba(248, 155, 41, 0.14); }
  }
}

.taxes-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: #f89b29;
  animation: pulse-dot 2s infinite;
  flex-shrink: 0;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50%       { opacity: 0.5; transform: scale(1.5); }
}

/* ── Tax Summary Section ─────────────────────────────────── */
.tax-summary-section {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.8rem 2rem;
  margin-top: 1.5rem;
}

.tax-summary-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 1rem;
  margin-bottom: 1.5rem;

  h2 { font-size: 1.15rem; font-weight: 800; color: var(--text-primary); margin: 0 0 0.3rem; }
}

.tax-summary-sub {
  font-size: 0.83rem;
  color: var(--text-muted);
  margin: 0;
}

.tax-summary-actions {
  display: flex;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.btn-mark-all {
  background: rgba(16, 185, 129, 0.1);
  color: var(--positive);
  border: 1px solid rgba(16, 185, 129, 0.3);
  border-radius: 8px;
  padding: 0.45rem 1rem;
  font-size: 0.83rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s;
  &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.18); }
  &:disabled { opacity: 0.5; cursor: wait; }

  &--all {
    background: rgba(16, 185, 129, 0.1);
    color: var(--accent);
    border-color: rgba(16, 185, 129, 0.3);
    &:hover:not(:disabled) { background: rgba(16, 185, 129, 0.18); }
  }
}

.tax-summary-loading {
  color: var(--text-muted);
  font-size: 0.88rem;
  padding: 1rem 0;
}

.tax-overview-cards {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
  margin-bottom: 1.8rem;
}

.tax-ov-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.8rem 1.3rem;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
  min-width: 150px;

  &--pending { border-color: rgba(248, 155, 41, 0.4); background: rgba(248, 155, 41, 0.05); }
  &--year    { border-color: rgba(240, 82, 82, 0.35); background: rgba(240, 82, 82, 0.04); }
  &--paid    { border-color: rgba(16, 185, 129, 0.3); background: rgba(16, 185, 129, 0.04); }
}

.tax-ov-label {
  font-size: 0.72rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.tax-ov-value {
  font-size: 1.05rem;
  font-weight: 700;
  color: var(--text-primary);
  &--green  { color: var(--positive); }
  &--accent { color: var(--accent); font-size: 0.9rem; }
}

.tax-empty {
  color: var(--text-secondary);
  font-size: 0.88rem;
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 1.2rem 1.5rem;
}

/* Per-holding groups */
.tax-holding-group {
  margin-bottom: 1.4rem;

  &:last-child { margin-bottom: 0; }
}

.tax-holding-header {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.6rem 0.8rem;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-bottom: none;
  border-radius: 10px 10px 0 0;
  font-size: 0.88rem;

  strong { color: var(--text-primary); font-size: 0.95rem; }
}

.tax-holding-name { color: var(--text-muted); font-size: 0.82rem; }

.tax-holding-pending {
  margin-left: auto;
  font-size: 0.78rem;
  font-weight: 700;
  color: #f89b29;
  background: rgba(248, 155, 41, 0.1);
  border: 1px solid rgba(248, 155, 41, 0.3);
  border-radius: 6px;
  padding: 0.15rem 0.55rem;
}

.tax-events-table-wrap {
  overflow-x: auto;
  border: 1px solid var(--border);
  border-radius: 0 0 10px 10px;
}

.tax-events-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.83rem;

  th {
    padding: 0.5rem 0.9rem;
    background: var(--bg-card);
    color: var(--text-secondary);
    font-weight: 600;
    text-align: left;
    white-space: nowrap;
  }

  td {
    padding: 0.55rem 0.9rem;
    color: var(--text-primary);
    border-top: 1px solid var(--border);
    white-space: nowrap;
  }

  tr.tax-row-pending td { background: rgba(248, 155, 41, 0.025); }
  tr.tax-row-paid td    { opacity: 0.65; }
}

.te-type-badge {
  display: inline-block;
  border-radius: 5px;
  padding: 0.15rem 0.5rem;
  font-size: 0.74rem;
  font-weight: 600;

  &--disposal {
    background: rgba(16, 185, 129, 0.12);
    color: var(--accent);
    border: 1px solid rgba(16, 185, 129, 0.25);
  }
  &--sell {
    background: rgba(5, 150, 105, 0.12);
    color: var(--accent-purple);
    border: 1px solid rgba(5, 150, 105, 0.25);
  }
}

.gain-pos { color: var(--positive); }
.gain-neg { color: var(--negative); }
.te-tax-amt { font-weight: 700; color: var(--negative); }

.te-status {
  display: inline-block;
  border-radius: 5px;
  padding: 0.15rem 0.5rem;
  font-size: 0.73rem;
  font-weight: 700;

  &--pending {
    background: rgba(248, 155, 41, 0.12);
    color: #f89b29;
    border: 1px solid rgba(248, 155, 41, 0.3);
  }
  &--paid {
    background: rgba(16, 185, 129, 0.1);
    color: var(--positive);
    border: 1px solid rgba(16, 185, 129, 0.25);
  }
}

.btn-te-paid {
  background: rgba(16, 185, 129, 0.1);
  color: var(--positive);
  border: 1px solid rgba(16, 185, 129, 0.3);
  border-radius: 5px;
  padding: 0.2rem 0.6rem;
  font-size: 0.74rem;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s;
  &:hover { background: rgba(16, 185, 129, 0.2); }
}

// Tax-free allowance input hint
.param-hint {
  display: block;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-top: 0.25rem;
}

// Tax-free allowance overview card
.tax-ov-card--allowance {
  background: rgba(16, 185, 129, 0.1);
  border: 1px solid rgba(16, 185, 129, 0.25);
}

// Tax-free allowance year breakdown
.tax-allowance-section {
  margin: 1rem 0 1.25rem;
  background: rgba(16, 185, 129, 0.06);
  border: 1px solid rgba(16, 185, 129, 0.18);
  border-radius: 10px;
  padding: 1rem 1.2rem;
}

.tax-allowance-header {
  font-size: 0.9rem;
  color: var(--text-secondary);
  margin-bottom: 0.75rem;
  strong { color: #10B981; }
}

.tax-allowance-rows {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-bottom: 0.75rem;
}

.tax-allowance-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 1.5rem;
  align-items: baseline;
  padding: 0.4rem 0.6rem;
  background: rgba(255, 255, 255, 0.03);
  border-radius: 6px;
  font-size: 0.84rem;
  color: var(--text-secondary);
  strong { color: var(--text-primary); }
}

.tax-allowance-year {
  font-weight: 700;
  color: var(--text-primary);
  min-width: 3rem;
}

.tax-allowance-deduct {
  color: #f89b29;
}

.tax-allowance-result strong {
  color: var(--positive);
}

.tax-allowance-total {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 0.6rem;
  border-top: 1px solid rgba(16, 185, 129, 0.2);
  font-size: 0.88rem;
  color: var(--text-secondary);
  strong {
    color: var(--positive);
    font-size: 1rem;
  }
}

/* ═══════════════════════════════════════════════
   LANDING PAGE – Full Stylesheet
   Extends global CSS variables from styles.scss
══════════════════════════════════════════════════ */

/* ── Helpers ── */
.container {
  max-width: 1180px;
  margin: 0 auto;
  padding: 0 1.5rem;
}

/* ── Shared buttons ── */
.lp-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.55rem;
  padding: 0.72rem 1.4rem;
  border-radius: 10px;
  border: none;
  font-family: inherit;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s, transform 0.15s, box-shadow 0.15s;
  text-decoration: none;

  &:hover { opacity: 0.88; transform: translateY(-2px); }
  &:active { transform: translateY(0); }

  &--primary {
    background: var(--accent);
    color: #fff;
    box-shadow: 0 4px 18px rgba(16, 185, 129, 0.35);
    &:hover { box-shadow: 0 8px 28px rgba(16, 185, 129, 0.45); }
  }
  &--outline {
    background: transparent;
    color: var(--text-primary);
    border: 1.5px solid var(--border-light);
    &:hover { border-color: var(--accent); color: var(--accent); }
  }
  &--ghost {
    background: rgba(16, 185, 129, 0.09);
    color: var(--accent);
    border: 1.5px solid rgba(16, 185, 129, 0.25);
    &:hover { background: rgba(16, 185, 129, 0.16); }
  }
  &--hero {
    background: var(--accent);
    color: #fff;
    font-size: 1.05rem;
    padding: 0.9rem 1.9rem;
    border-radius: 12px;
    box-shadow: 0 6px 28px rgba(16, 185, 129, 0.4);
    &:hover { box-shadow: 0 10px 36px rgba(16, 185, 129, 0.55); }
  }
  &--github {
    background: #24292e;
    color: #fff;
    border: 1px solid #24292e;
    padding: 0.85rem 1.6rem;
    font-size: 1rem;
    &:hover { background: #1a1f24; }
  }
  &--google {
    background: var(--bg-elevated);
    color: var(--text-primary);
    border: 1.5px solid var(--border-light);
    padding: 0.85rem 1.6rem;
    font-size: 1rem;
  }
}

/* ── Section header ── */
.section-header {
  text-align: center;
  margin-bottom: 3.5rem;

  h2 {
    font-size: clamp(1.7rem, 3vw, 2.4rem);
    font-weight: 800;
    letter-spacing: -0.03em;
    color: var(--text-primary);
    margin: 0.5rem 0 0.9rem;
  }
  p {
    color: var(--text-secondary);
    font-size: 1.05rem;
    max-width: 520px;
    margin: 0 auto;
    line-height: 1.7;
  }
}

.section-tag {
  display: inline-block;
  background: rgba(16, 185, 129, 0.12);
  color: var(--accent);
  border: 1px solid rgba(16, 185, 129, 0.28);
  border-radius: 100px;
  padding: 0.28rem 0.9rem;
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ═══════════════════════════════════════════
   SCROLL REVEAL ANIMATION
══════════════════════════════════════════════ */
.reveal {
  opacity: 0;
  transform: translateY(28px);
  transition: opacity 0.65s ease, transform 0.65s ease;
  transition-delay: var(--delay, 0s);

  &.is-visible {
    opacity: 1;
    transform: translateY(0);
  }
}

/* ═══════════════════════════════════════════
   STICKY NAV
══════════════════════════════════════════════ */
.lp-nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  transition: background 0.25s, backdrop-filter 0.25s, box-shadow 0.25s;

  &__inner {
    max-width: 1180px;
    margin: 0 auto;
    padding: 1.1rem 1.5rem;
    display: flex;
    align-items: center;
    gap: 2rem;
  }

  &__brand {
    display: flex;
    align-items: center;
    gap: 0.55rem;
    flex: 1;
  }
  &__brand-logo {
    height: 32px;
    width: auto;
    object-fit: contain;
    display: block;
  }
  &__brand-name {
    font-size: 1.05rem;
    font-weight: 800;
    color: var(--text-primary);
    letter-spacing: -0.02em;
  }

  &__links {
    display: flex;
    align-items: center;
    gap: 2rem;
    a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: 0.9rem;
      font-weight: 500;
      transition: color 0.15s;
      &:hover { color: var(--text-primary); }
    }
  }

  &--scrolled {
    background: rgba(15, 23, 42, 0.85);
    backdrop-filter: blur(20px);
    box-shadow: 0 1px 0 rgba(229, 231, 235, 0.15), var(--shadow-md);
    .lp-nav__inner { padding-top: 0.8rem; padding-bottom: 0.8rem; }
  }
}

/* ═══════════════════════════════════════════
   HERO
══════════════════════════════════════════════ */
.hero {
  position: relative;
  min-height: 100vh;
  display: flex;
  align-items: center;
  overflow: hidden;
  background: linear-gradient(160deg, #0F172A 0%, #1a2540 50%, #0F172A 100%);

  &__bg-svg {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
  }

  &__content {
    position: relative;
    z-index: 1;
    max-width: 1180px;
    margin: 0 auto;
    padding: 8rem 1.5rem 5rem;
    max-width: 720px;
  }

  &__badge {
    display: inline-flex;
    align-items: center;
    gap: 0.55rem;
    background: rgba(16, 185, 129, 0.1);
    border: 1px solid rgba(16, 185, 129, 0.25);
    border-radius: 100px;
    padding: 0.35rem 1rem;
    font-size: 0.82rem;
    color: var(--accent);
    font-weight: 500;
    margin-bottom: 1.8rem;
  }

  &__badge-pulse {
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: var(--accent);
    animation: pulse 2s infinite;
  }

  &__headline {
    font-size: clamp(2.6rem, 6vw, 4.2rem);
    font-weight: 900;
    line-height: 1.1;
    letter-spacing: -0.04em;
    color: var(--text-primary);
    margin-bottom: 1.4rem;
  }

  &__accent {
    background: linear-gradient(130deg, var(--accent) 0%, var(--accent-purple) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  &__sub {
    font-size: clamp(1rem, 1.8vw, 1.18rem);
    color: var(--text-secondary);
    line-height: 1.75;
    max-width: 580px;
    margin-bottom: 2.2rem;
  }

  &__irish-highlight {
    max-width: 620px;
    border: 1px solid rgba(46, 196, 182, 0.42);
    background: linear-gradient(140deg, rgba(46, 196, 182, 0.18) 0%, rgba(16, 185, 129, 0.1) 100%);
    border-radius: 14px;
    padding: 1rem 1.2rem;
    margin-bottom: 2.1rem;
    box-shadow: 0 12px 34px rgba(46, 196, 182, 0.16);

    h3 {
      margin: 0.45rem 0 0.5rem;
      font-size: clamp(1.03rem, 1.6vw, 1.2rem);
      line-height: 1.35;
      color: var(--text-primary);
      letter-spacing: -0.01em;
    }

    p {
      margin: 0;
      color: var(--text-secondary);
      font-size: 0.92rem;
      line-height: 1.6;
    }
  }

  &__irish-highlight-label {
    display: inline-flex;
    border-radius: 999px;
    background: rgba(46, 196, 182, 0.18);
    border: 1px solid rgba(46, 196, 182, 0.35);
    color: #8ce6da;
    font-size: 0.72rem;
    font-weight: 700;
    letter-spacing: 0.05em;
    text-transform: uppercase;
    padding: 0.24rem 0.62rem;
  }

  &__cta {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-wrap: wrap;
    margin-bottom: 3rem;
  }

  &__stats {
    display: flex;
    align-items: center;
    gap: 0;
    flex-wrap: wrap;
    gap: 0.5rem;
  }

  &__stat {
    display: flex;
    flex-direction: column;
  }
  &__stat-val {
    font-size: 0.92rem;
    font-weight: 700;
    color: var(--text-primary);
  }
  &__stat-lbl {
    font-size: 0.75rem;
    color: var(--text-muted);
  }
  &__stat-sep {
    width: 1px;
    height: 32px;
    background: var(--border);
    margin: 0 1.4rem;
  }

  &__scroll-hint {
    position: absolute;
    bottom: 2.5rem;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.4rem;
    color: var(--text-muted);
    font-size: 0.78rem;
    cursor: pointer;
    animation: bob 2.5s ease-in-out infinite;
    &:hover { color: var(--text-secondary); }
  }
}

/* Hero chart animations */
.hero-line-1 {
  stroke-dasharray: 2200;
  stroke-dashoffset: 2200;
  animation: drawLine 3.5s ease forwards 0.4s;
}
.hero-line-2 {
  stroke-dasharray: 2100;
  stroke-dashoffset: 2100;
  animation: drawLine 4s ease forwards 0.8s;
}
.hero-dot-1 {
  opacity: 0;
  animation: fadeIn 0.4s ease forwards 3.8s;
}
.hero-dot-2 {
  opacity: 0;
  animation: fadeIn 0.4s ease forwards 4.5s;
}

/* ═══════════════════════════════════════════
   FEATURES
══════════════════════════════════════════════ */
.features {
  padding: 7rem 0;
  background: var(--bg-base);

  &__grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(310px, 1fr));
    gap: 1.25rem;
  }
}

.feature-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.8rem;
  transition: border-color 0.2s, box-shadow 0.2s, transform 0.2s;

  &:hover {
    border-color: var(--border-light);
    box-shadow: var(--shadow-lg);
    transform: translateY(-3px);
  }

  h3 {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.5rem;
  }
  p {
    font-size: 0.9rem;
    color: var(--text-secondary);
    line-height: 1.7;
    margin: 0;
  }

  &__icon {
    width: 46px;
    height: 46px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1.1rem;
    svg { width: 22px; height: 22px; }

    &--blue   { background: rgba(16, 185, 129, 0.14); color: var(--accent); svg { stroke: var(--accent); } }
    &--green  { background: rgba(16, 185, 129, 0.12); color: var(--positive); svg { stroke: var(--positive); } }
    &--purple { background: rgba(5, 150, 105, 0.14); color: var(--accent-purple); svg { stroke: var(--accent-purple); } }
    &--cyan   { background: rgba(52, 211, 153, 0.12);  color: var(--accent-cyan); svg { stroke: var(--accent-cyan); } }
    &--amber  { background: rgba(248, 155, 41, 0.12); color: #f89b29; svg { stroke: #f89b29; } }
    &--red    { background: rgba(240, 82, 82, 0.12);  color: var(--negative); svg { stroke: var(--negative); } }
  }
}

/* ═══════════════════════════════════════════
   APP PREVIEW
══════════════════════════════════════════════ */
.preview {
  padding: 7rem 0;
  background: var(--bg-surface);

  &__tabs {
    display: flex;
    justify-content: center;
    gap: 0.5rem;
    margin-bottom: 2rem;
    flex-wrap: wrap;
  }

  &__tab {
    background: var(--bg-card);
    border: 1.5px solid var(--border);
    color: var(--text-secondary);
    border-radius: 8px;
    padding: 0.5rem 1.2rem;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    font-family: inherit;
    transition: all 0.2s;

    &.active, &:hover {
      border-color: var(--accent);
      color: var(--accent);
      background: rgba(16, 185, 129, 0.1);
    }
  }

  &__browser {
    border-radius: 14px;
    overflow: hidden;
    border: 1px solid var(--border-light);
    box-shadow: 0 40px 100px rgba(0, 0, 0, 0.7), 0 0 0 1px rgba(16, 185, 129, 0.08);
    animation: float 6s ease-in-out infinite;
  }

  &__titlebar {
    background: #1E293B;
    border-bottom: 1px solid var(--border);
    padding: 0.7rem 1.1rem;
    display: flex;
    align-items: center;
    gap: 0.4rem;
  }

  &__dot {
    width: 11px;
    height: 11px;
    border-radius: 50%;
    &--red    { background: #ff5f57; }
    &--yellow { background: #febc2e; }
    &--green  { background: #28c840; }
  }

  &__url {
    margin-left: 0.8rem;
    font-size: 0.78rem;
    color: var(--text-muted);
    background: var(--bg-elevated);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 0.2rem 0.75rem;
  }

  &__slide {
    display: none;
    &.active { display: block; }
  }

  &__svg {
    display: block;
    width: 100%;
    height: auto;
  }
}

/* ═══════════════════════════════════════════
   FEATURE SPOTLIGHTS
══════════════════════════════════════════════ */
.spotlight {
  padding: 7rem 0;
  background: var(--bg-base);

  &--alt {
    background: var(--bg-surface);
  }

  &__inner {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4rem;
    align-items: center;

    &--reversed {
      .spotlight__visual { order: -1; }
    }
  }

  &__text {
    .section-tag { margin-bottom: 1rem; display: block; }
    h2 {
      font-size: clamp(1.7rem, 3vw, 2.3rem);
      font-weight: 800;
      letter-spacing: -0.03em;
      color: var(--text-primary);
      margin-bottom: 1.1rem;
      line-height: 1.25;
    }
    p {
      color: var(--text-secondary);
      font-size: 1rem;
      line-height: 1.8;
      margin-bottom: 1.6rem;
    }
  }

  &__list {
    list-style: none;
    margin: 0 0 2rem;
    padding: 0;
    display: flex;
    flex-direction: column;
    gap: 0.7rem;

    li {
      display: flex;
      align-items: center;
      gap: 0.7rem;
      font-size: 0.93rem;
      color: var(--text-secondary);
      svg { width: 18px; height: 18px; flex-shrink: 0; }
    }
  }

  &__visual {
    position: relative;
  }
}

/* Projection chart demo card */
.proj-chart-demo {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: var(--shadow-lg);
  animation: float 7s ease-in-out infinite;

  &__header {
    background: var(--bg-elevated);
    border-bottom: 1px solid var(--border);
    padding: 0.85rem 1.2rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-size: 0.88rem;
    font-weight: 700;
    color: var(--text-primary);
  }

  &__legend {
    display: flex;
    align-items: center;
    gap: 1rem;
    font-size: 0.78rem;
    font-weight: 500;
    color: var(--text-secondary);
  }

  &__body {
    padding: 1rem 1.4rem 0;
    svg { width: 100%; height: auto; }
  }

  &__footer {
    display: flex;
    justify-content: space-between;
    padding: 1rem 1.4rem 1.2rem;
    border-top: 1px solid var(--border);
    flex-wrap: wrap;
    gap: 0.8rem;
  }
}

.dot-blue {
  width: 8px; height: 8px; border-radius: 50%;
  background: var(--accent); display: inline-block;
}
.dot-green {
  width: 8px; height: 8px; border-radius: 50%;
  background: var(--positive); display: inline-block;
}

.proj-stat {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;

  &__val {
    font-size: 0.95rem;
    font-weight: 700;
    color: var(--text-primary);
    &--green { color: var(--positive); }
    &--red   { color: var(--negative); }
  }
  &__lbl {
    font-size: 0.73rem;
    color: var(--text-muted);
  }
}

/* Projection chart SVG animations */
.anim-line-1 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.5s ease forwards 0.3s;
}
.anim-line-2 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.8s ease forwards 0.6s;
}
.proj-line-1 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.5s ease forwards 0.3s;
}
.proj-line-2 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.8s ease forwards 0.6s;
}

/* ═══════════════════════════════════════════
   IRISH TAX CARD
══════════════════════════════════════════════ */
.tax-card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: var(--shadow-lg);
  animation: float 7s ease-in-out infinite 1s;

  &__header {
    background: var(--bg-elevated);
    border-bottom: 1px solid var(--border);
    padding: 1rem 1.4rem;
    font-size: 0.95rem;
    font-weight: 700;
    color: var(--text-primary);
  }

  &__body {
    padding: 0.8rem 1.4rem;
  }

  &__footer {
    background: var(--bg-elevated);
    border-top: 1px solid var(--border);
    padding: 0.75rem 1.4rem;
    font-size: 0.78rem;
    color: var(--text-muted);
    text-align: center;
  }
}

.tax-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.6rem 0;
  border-bottom: 1px solid rgba(229, 231, 235, 0.5);

  &:last-child { border-bottom: none; }

  &--divider { padding: 0.2rem 0; }

  &--total {
    margin-top: 0.3rem;
    border-top: 1px solid var(--border-light);
    padding-top: 0.9rem;
    .tax-row__label { font-weight: 700; color: var(--text-primary); }
    .tax-row__value { font-size: 1.1rem; font-weight: 800; }
  }

  &__label {
    font-size: 0.88rem;
    color: var(--text-secondary);
  }

  &__value {
    font-size: 0.92rem;
    font-weight: 600;
    color: var(--text-primary);
    &--pos { color: var(--positive); }
    &--neg { color: var(--negative); }
  }
}

.tax-badge {
  display: inline-block;
  background: rgba(240, 82, 82, 0.12);
  color: var(--negative);
  border: 1px solid rgba(240, 82, 82, 0.28);
  border-radius: 6px;
  padding: 0.2rem 0.6rem;
  font-size: 0.76rem;
  font-weight: 700;
}

/* ═══════════════════════════════════════════
   HOW IT WORKS
══════════════════════════════════════════════ */
.how {
  padding: 7rem 0;
  background: var(--bg-surface);

  &__steps {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
    gap: 1rem;
  }

  &__step {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 2rem 1.8rem;
    flex: 1;
    min-width: 220px;
    max-width: 280px;
    text-align: center;
    transition: border-color 0.2s, transform 0.2s;

    &:hover {
      border-color: var(--accent);
      transform: translateY(-4px);
    }

    h3 {
      font-size: 1.05rem;
      font-weight: 700;
      color: var(--text-primary);
      margin-bottom: 0.6rem;
    }
    p {
      font-size: 0.88rem;
      color: var(--text-secondary);
      line-height: 1.7;
      margin: 0;
    }
  }

  &__step-num {
    font-size: 0.75rem;
    font-weight: 800;
    letter-spacing: 0.08em;
    color: var(--accent);
    opacity: 0.7;
    margin-bottom: 0.8rem;
  }

  &__step-icon {
    width: 52px;
    height: 52px;
    background: rgba(16, 185, 129, 0.1);
    border-radius: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 1.1rem;
    svg {
      width: 24px;
      height: 24px;
      stroke: var(--accent);
    }
  }

  &__connector {
    width: 48px;
    height: 1.5px;
    background: linear-gradient(90deg, transparent, var(--border-light), transparent);
    flex-shrink: 0;

    @media (max-width: 720px) { display: none; }
  }
}

/* ═══════════════════════════════════════════
   FINAL CTA
══════════════════════════════════════════════ */
.cta-section {
  position: relative;
  padding: 8rem 0;
  background: var(--bg-base);
  overflow: hidden;
  text-align: center;

  &__glow {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 700px;
    height: 400px;
    background: radial-gradient(ellipse at center, rgba(16, 185, 129, 0.12) 0%, transparent 70%);
    pointer-events: none;
  }

  &__inner {
    position: relative;
    z-index: 1;

    h2 {
      font-size: clamp(1.9rem, 4vw, 2.9rem);
      font-weight: 900;
      letter-spacing: -0.03em;
      color: var(--text-primary);
      margin-bottom: 1rem;
    }
    p {
      color: var(--text-secondary);
      font-size: 1.05rem;
      margin-bottom: 2.4rem;
    }
  }

  &__btns {
    display: flex;
    justify-content: center;
    gap: 1rem;
    flex-wrap: wrap;
    margin-bottom: 1.4rem;
  }

  &__note {
    font-size: 0.82rem;
    color: var(--text-muted);
    margin-top: 1rem;
  }
}

/* ═══════════════════════════════════════════
   FOOTER
══════════════════════════════════════════════ */
.lp-footer {
  background: var(--bg-surface);
  border-top: 1px solid var(--border);
  padding: 2.5rem 0;

  &__inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 1rem;
  }

  &__brand {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: 700;
    color: var(--text-primary);
    font-size: 0.95rem;
  }
  &__brand-logo {
    height: 28px;
    width: auto;
    object-fit: contain;
  }
  &__icon { font-size: 1.2rem; }

  &__copy {
    color: var(--text-muted);
    font-size: 0.82rem;
    margin: 0;
  }

  &__links {
    display: flex;
    gap: 1.5rem;
    a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: 0.85rem;
      transition: color 0.15s;
      &:hover { color: var(--text-primary); }
    }
  }
}

/* ═══════════════════════════════════════════
   SIA ANNOUNCEMENT BANNER
══════════════════════════════════════════════ */
.sia-banner {
  background: linear-gradient(90deg, rgba(46,196,182,0.08) 0%, rgba(46,196,182,0.04) 100%);
  border-bottom: 1px solid rgba(46,196,182,0.2);
  padding: 0.85rem 0;

  &__inner {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-wrap: wrap;
  }

  &__flag { font-size: 1.4rem; flex-shrink: 0; }

  &__text {
    flex: 1;
    font-size: 0.88rem;
    color: var(--text-secondary);
    line-height: 1.5;
    strong { color: var(--text-primary); }
  }
}

.lp-btn--sia {
  background: rgba(46,196,182,0.15);
  color: #2ec4b6;
  border: 1.5px solid rgba(46,196,182,0.35);
  padding: 0.55rem 1.1rem;
  font-size: 0.85rem;
  white-space: nowrap;
  flex-shrink: 0;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s, transform 0.15s;
  &:hover { background: rgba(46,196,182,0.25); transform: translateY(-1px); }
}

/* ═══════════════════════════════════════════
   FEATURE CARD HIGHLIGHTED (SIA card)
══════════════════════════════════════════════ */
.feature-card--highlighted {
  border-color: rgba(46,196,182,0.35);
  background: linear-gradient(145deg, var(--bg-card) 0%, rgba(46,196,182,0.04) 100%);
  position: relative;

  &:hover { border-color: #2ec4b6; }
}

.feature-card__badge {
  position: absolute;
  top: 1rem;
  right: 1rem;
  background: rgba(46,196,182,0.15);
  color: #2ec4b6;
  border: 1px solid rgba(46,196,182,0.35);
  border-radius: 20px;
  padding: 0.18rem 0.65rem;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.04em;
}

.feature-card__icon--emerald {
  background: rgba(46,196,182,0.12);
  color: #2ec4b6;
  svg { stroke: #2ec4b6; }
}

.section-tag--ireland {
  background: rgba(46,196,182,0.1);
  color: #2ec4b6;
  border-color: rgba(46,196,182,0.28);
}

/* ═══════════════════════════════════════════
   IRISH TAX PROBLEM SECTION
══════════════════════════════════════════════ */
.tax-problem {
  padding: 7rem 0;
  background: var(--bg-surface);
}

.tax-compare {
  display: grid;
  grid-template-columns: 1fr auto 1fr;
  gap: 0;
  align-items: stretch;
  margin-bottom: 3rem;

  @media (max-width: 900px) {
    grid-template-columns: 1fr;
  }

  &__card {
    border-radius: 16px;
    overflow: hidden;
    display: flex;
    flex-direction: column;

    &--problem {
      border: 1.5px solid rgba(240,82,82,0.35);
      background: var(--bg-card);
    }
    &--solution {
      border: 1.5px solid rgba(46,196,182,0.35);
      background: var(--bg-card);
    }
  }

  &__card-header {
    padding: 1.6rem 1.8rem 1.2rem;
    border-bottom: 1px solid var(--border);

    h3 {
      font-size: 1.2rem;
      font-weight: 800;
      color: var(--text-primary);
      margin: 0.5rem 0 0.3rem;
    }
    p {
      font-size: 0.85rem;
      color: var(--text-muted);
      margin: 0;
    }
  }

  &__card-body {
    padding: 0.5rem 1.8rem;
    flex: 1;
  }

  &__card-footer {
    padding: 0.9rem 1.8rem;
    font-size: 0.8rem;
    text-align: center;
    font-weight: 500;

    &--bad {
      background: rgba(240,82,82,0.07);
      border-top: 1px solid rgba(240,82,82,0.2);
      color: #f05252;
    }
    &--good {
      background: rgba(46,196,182,0.07);
      border-top: 1px solid rgba(46,196,182,0.2);
      color: #2ec4b6;
    }
  }

  &__regime-badge {
    display: inline-block;
    border-radius: 20px;
    padding: 0.22rem 0.75rem;
    font-size: 0.75rem;
    font-weight: 700;
    letter-spacing: 0.04em;

    &--current {
      background: rgba(240,82,82,0.12);
      color: #f05252;
      border: 1px solid rgba(240,82,82,0.3);
    }
    &--sia {
      background: rgba(46,196,182,0.12);
      color: #2ec4b6;
      border: 1px solid rgba(46,196,182,0.3);
    }
  }

  &__row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.65rem 0;
    border-bottom: 1px solid rgba(229,231,235,0.4);
    gap: 1rem;
    flex-wrap: wrap;

    &:last-child { border-bottom: none; }
  }

  &__label {
    font-size: 0.84rem;
    color: var(--text-secondary);
    flex-shrink: 0;
  }

  &__value {
    font-size: 0.84rem;
    font-weight: 600;
    color: var(--text-primary);
    text-align: right;

    &--bad  { color: #f05252; }
    &--good { color: #2ec4b6; }
  }

  &__vs {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 0 1.5rem;
    gap: 0.5rem;

    span {
      font-size: 1.1rem;
      font-weight: 900;
      color: var(--text-muted);
      letter-spacing: 0.1em;
    }

    @media (max-width: 900px) {
      flex-direction: row;
      padding: 1rem 0;
    }
  }

  &__arrow {
    font-size: 1.4rem;
    color: rgba(16,185,129,0.4);
    @media (max-width: 900px) { transform: rotate(90deg); }
  }

  &__year {
    background: rgba(16,185,129,0.12);
    color: var(--accent);
    border: 1px solid rgba(16,185,129,0.25);
    border-radius: 20px;
    padding: 0.2rem 0.65rem;
    font-size: 0.8rem !important;
    font-weight: 700 !important;
    letter-spacing: 0.04em;
  }
}

.tax-cta {
  display: flex;
  align-items: center;
  gap: 2rem;
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 14px;
  padding: 1.6rem 2rem;
  flex-wrap: wrap;

  &__text {
    flex: 1;
    font-size: 0.93rem;
    color: var(--text-secondary);
    line-height: 1.7;
    strong { color: var(--text-primary); }
  }
}

/* ═══════════════════════════════════════════
   FOR GLOBAL INVESTORS
══════════════════════════════════════════════ */
.global-investors {
  padding: 7rem 0;
  background: var(--bg-base);
}

.global-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 1.25rem;
}

.global-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.8rem;
  transition: border-color 0.2s, box-shadow 0.2s, transform 0.2s;

  &:hover {
    border-color: var(--border-light);
    box-shadow: var(--shadow-lg);
    transform: translateY(-3px);
  }

  &__icon {
    width: 46px;
    height: 46px;
    border-radius: 12px;
    background: rgba(16,185,129,0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1.1rem;
    svg { width: 22px; height: 22px; stroke: var(--accent); }
  }

  h3 {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.5rem;
  }
  p {
    font-size: 0.9rem;
    color: var(--text-secondary);
    line-height: 1.7;
    margin: 0;
  }
}

/* CTA tagline */
.cta-section__tagline {
  font-size: 0.88rem;
  color: #2ec4b6;
  margin-top: -1rem;
  margin-bottom: 2rem;
  font-weight: 500;
}

/* ═══════════════════════════════════════════
   KEYFRAMES
══════════════════════════════════════════════ */
@keyframes drawLine {
  to { stroke-dashoffset: 0; }
}

@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50%       { transform: scale(1.6); opacity: 0.5; }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes bob {
  0%, 100% { transform: translateX(-50%) translateY(0); }
  50%       { transform: translateX(-50%) translateY(6px); }
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50%       { transform: translateY(-8px); }
}

/* ═══════════════════════════════════════════
   RESPONSIVE
══════════════════════════════════════════════ */
@media (max-width: 900px) {
  .spotlight__inner {
    grid-template-columns: 1fr;
    gap: 2.5rem;

    &--reversed .spotlight__visual { order: unset; }
  }

  .lp-nav__links { display: none; }

  .hero__content { padding-top: 6rem; }
}

@media (max-width: 600px) {
  .hero__stats { flex-direction: column; gap: 1rem; }
  .hero__stat-sep { display: none; }
  .features__grid { grid-template-columns: 1fr; }
  .lp-footer__inner { flex-direction: column; text-align: center; }
  .how__steps { flex-direction: column; align-items: center; }
  .how__connector { display: none; }
}

/* ═══════════════════════════════════════════════
   LANDING PAGE – Full Stylesheet
   Extends global CSS variables from styles.scss
══════════════════════════════════════════════════ */

:host {
  --bg-base: #334155;
  --bg-surface: #475569;
  --bg-card: #475569;
  --bg-elevated: #64748B;
}

/* ── Helpers ── */
.container {
  max-width: 1180px;
  margin: 0 auto;
  padding: 0 1.5rem;
}

/* ── Shared buttons ── */
.lp-btn {
  display: inline-flex;
  align-items: center;
  gap: 0.55rem;
  padding: 0.72rem 1.4rem;
  border-radius: 10px;
  border: none;
  font-family: inherit;
  font-size: 0.95rem;
  font-weight: 600;
  cursor: pointer;
  transition: opacity 0.15s, transform 0.15s, box-shadow 0.15s;
  text-decoration: none;

  &:hover { opacity: 0.88; transform: translateY(-2px); }
  &:active { transform: translateY(0); }

  &--primary {
    background: var(--accent);
    color: #fff;
    box-shadow: 0 4px 18px rgba(16, 185, 129, 0.35);
    &:hover { box-shadow: 0 8px 28px rgba(16, 185, 129, 0.45); }
  }
  &--outline {
    background: transparent;
    color: var(--text-primary);
    border: 1.5px solid var(--border-light);
    &:hover { border-color: var(--accent); color: var(--accent); }
  }
  &--ghost {
    background: rgba(16, 185, 129, 0.09);
    color: var(--accent);
    border: 1.5px solid rgba(16, 185, 129, 0.25);
    &:hover { background: rgba(16, 185, 129, 0.16); }
  }
  &--hero {
    background: var(--accent);
    color: #fff;
    font-size: 1.05rem;
    padding: 0.9rem 1.9rem;
    border-radius: 12px;
    box-shadow: 0 6px 28px rgba(16, 185, 129, 0.4);
    &:hover { box-shadow: 0 10px 36px rgba(16, 185, 129, 0.55); }
  }
  &--github {
    background: #24292e;
    color: #fff;
    border: 1px solid #24292e;
    padding: 0.85rem 1.6rem;
    font-size: 1rem;
    &:hover { background: #1a1f24; }
  }
  &--google {
    background: var(--bg-elevated);
    color: var(--text-primary);
    border: 1.5px solid var(--border-light);
    padding: 0.85rem 1.6rem;
    font-size: 1rem;
  }
}

/* ── Section header ── */
.section-header {
  text-align: center;
  margin-bottom: 3.5rem;

  h2 {
    font-size: clamp(1.7rem, 3vw, 2.4rem);
    font-weight: 800;
    letter-spacing: -0.03em;
    color: var(--text-primary);
    margin: 0.5rem 0 0.9rem;
  }
  p {
    color: var(--text-secondary);
    font-size: 1.05rem;
    max-width: 520px;
    margin: 0 auto;
    line-height: 1.7;
  }
}

.section-tag {
  display: inline-block;
  background: rgba(16, 185, 129, 0.12);
  color: var(--accent);
  border: 1px solid rgba(16, 185, 129, 0.28);
  border-radius: 100px;
  padding: 0.28rem 0.9rem;
  font-size: 0.78rem;
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ═══════════════════════════════════════════
   SCROLL REVEAL ANIMATION
══════════════════════════════════════════════ */
.reveal {
  opacity: 0;
  transform: translateY(28px);
  transition: opacity 0.65s ease, transform 0.65s ease;
  transition-delay: var(--delay, 0s);

  &.is-visible {
    opacity: 1;
    transform: translateY(0);
  }
}

/* ═══════════════════════════════════════════
   STICKY NAV
══════════════════════════════════════════════ */
.lp-nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  transition: background 0.25s, backdrop-filter 0.25s, box-shadow 0.25s;

  &__inner {
    max-width: 1180px;
    margin: 0 auto;
    padding: 1.1rem 1.5rem;
    display: flex;
    align-items: center;
    gap: 2rem;
  }

  &__brand {
    display: flex;
    align-items: center;
    gap: 0.55rem;
    flex: 1;
  }
  &__brand-logo {
    height: 60px;
    width: auto;
    object-fit: contain;
    display: block;
  }
  &__brand-name {
    font-size: 1.05rem;
    font-weight: 800;
    color: var(--text-primary);
    letter-spacing: -0.02em;
  }

  &__links {
    display: flex;
    align-items: center;
    gap: 2rem;
    a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: 0.9rem;
      font-weight: 500;
      transition: color 0.15s;
      &:hover { color: var(--text-primary); }
    }
  }

  &--scrolled {
    background: rgba(15, 23, 42, 0.85);
    backdrop-filter: blur(20px);
    box-shadow: 0 1px 0 rgba(229, 231, 235, 0.15), var(--shadow-md);
    .lp-nav__inner { padding-top: 0.8rem; padding-bottom: 0.8rem; }
  }
}

/* ═══════════════════════════════════════════
   HERO
══════════════════════════════════════════════ */
.hero {
  position: relative;
  min-height: 100vh;
  display: flex;
  align-items: center;
  overflow: hidden;
  background: linear-gradient(160deg, #0F172A 0%, #1a2540 50%, #0F172A 100%);

  &__bg-svg {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
  }

  &__content {
    position: relative;
    z-index: 1;
    max-width: 1180px;
    margin: 0 auto;
    padding: 8rem 1.5rem 5rem;
    max-width: 720px;
  }

  &__badge {
    display: inline-flex;
    align-items: center;
    gap: 0.55rem;
    background: rgba(16, 185, 129, 0.1);
    border: 1px solid rgba(16, 185, 129, 0.25);
    border-radius: 100px;
    padding: 0.35rem 1rem;
    font-size: 0.82rem;
    color: var(--accent);
    font-weight: 500;
    margin-bottom: 1.8rem;
  }

  &__badge-pulse {
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: var(--accent);
    animation: pulse 2s infinite;
  }

  &__headline {
    font-size: clamp(2.6rem, 6vw, 4.2rem);
    font-weight: 900;
    line-height: 1.1;
    letter-spacing: -0.04em;
    color: var(--text-primary);
    margin-bottom: 1.4rem;
  }

  &__accent {
    background: linear-gradient(130deg, var(--accent) 0%, var(--accent-purple) 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
  }

  &__sub {
    font-size: clamp(1rem, 1.8vw, 1.18rem);
    color: var(--text-secondary);
    line-height: 1.75;
    max-width: 580px;
    margin-bottom: 2.2rem;
  }

  &__irish-highlight {
    max-width: 620px;
    border: 1px solid rgba(46, 196, 182, 0.42);
    background: linear-gradient(140deg, rgba(46, 196, 182, 0.18) 0%, rgba(16, 185, 129, 0.1) 100%);
    border-radius: 14px;
    padding: 1rem 1.2rem;
    margin-bottom: 2.1rem;
    box-shadow: 0 12px 34px rgba(46, 196, 182, 0.16);

    h3 {
      margin: 0.45rem 0 0.5rem;
      font-size: clamp(1.03rem, 1.6vw, 1.2rem);
      line-height: 1.35;
      color: var(--text-primary);
      letter-spacing: -0.01em;
    }

    p {
      margin: 0;
      color: var(--text-secondary);
      font-size: 0.92rem;
      line-height: 1.6;
    }
  }

  &__irish-highlight-label {
    display: inline-flex;
    border-radius: 999px;
    background: rgba(46, 196, 182, 0.18);
    border: 1px solid rgba(46, 196, 182, 0.35);
    color: #8ce6da;
    font-size: 0.72rem;
    font-weight: 700;
    letter-spacing: 0.05em;
    text-transform: uppercase;
    padding: 0.24rem 0.62rem;
  }

  &__cta {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-wrap: wrap;
    margin-bottom: 3rem;
  }

  &__stats {
    display: flex;
    align-items: center;
    gap: 0;
    flex-wrap: wrap;
    gap: 0.5rem;
  }

  &__stat {
    display: flex;
    flex-direction: column;
  }
  &__stat-val {
    font-size: 0.92rem;
    font-weight: 700;
    color: var(--text-primary);
  }
  &__stat-lbl {
    font-size: 0.75rem;
    color: var(--text-muted);
  }
  &__stat-sep {
    width: 1px;
    height: 32px;
    background: var(--border);
    margin: 0 1.4rem;
  }

  &__scroll-hint {
    position: absolute;
    bottom: 2.5rem;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.4rem;
    color: var(--text-muted);
    font-size: 0.78rem;
    cursor: pointer;
    animation: bob 2.5s ease-in-out infinite;
    &:hover { color: var(--text-secondary); }
  }
}

/* Hero chart animations */
.hero-line-1 {
  stroke-dasharray: 2200;
  stroke-dashoffset: 2200;
  animation: drawLine 3.5s ease forwards 0.4s;
}
.hero-line-2 {
  stroke-dasharray: 2100;
  stroke-dashoffset: 2100;
  animation: drawLine 4s ease forwards 0.8s;
}
.hero-dot-1 {
  opacity: 0;
  animation: fadeIn 0.4s ease forwards 3.8s;
}
.hero-dot-2 {
  opacity: 0;
  animation: fadeIn 0.4s ease forwards 4.5s;
}

/* ═══════════════════════════════════════════
   FEATURES
══════════════════════════════════════════════ */
.features {
  padding: 7rem 0;
  background: var(--bg-base);

  &__grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(310px, 1fr));
    gap: 1.25rem;
  }
}

.feature-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.8rem;
  transition: border-color 0.2s, box-shadow 0.2s, transform 0.2s;

  &:hover {
    border-color: var(--border-light);
    box-shadow: var(--shadow-lg);
    transform: translateY(-3px);
  }

  h3 {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.5rem;
  }
  p {
    font-size: 0.9rem;
    color: var(--text-secondary);
    line-height: 1.7;
    margin: 0;
  }

  &__icon {
    width: 46px;
    height: 46px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1.1rem;
    svg { width: 22px; height: 22px; }

    &--blue   { background: rgba(16, 185, 129, 0.14); color: var(--accent); svg { stroke: var(--accent); } }
    &--green  { background: rgba(16, 185, 129, 0.12); color: var(--positive); svg { stroke: var(--positive); } }
    &--purple { background: rgba(5, 150, 105, 0.14); color: var(--accent-purple); svg { stroke: var(--accent-purple); } }
    &--cyan   { background: rgba(52, 211, 153, 0.12);  color: var(--accent-cyan); svg { stroke: var(--accent-cyan); } }
    &--amber  { background: rgba(248, 155, 41, 0.12); color: #f89b29; svg { stroke: #f89b29; } }
    &--red    { background: rgba(240, 82, 82, 0.12);  color: var(--negative); svg { stroke: var(--negative); } }
  }
}

/* ═══════════════════════════════════════════
   APP PREVIEW
══════════════════════════════════════════════ */
.preview {
  padding: 7rem 0;
  background: var(--bg-surface);

  &__tabs {
    display: flex;
    justify-content: center;
    gap: 0.5rem;
    margin-bottom: 2rem;
    flex-wrap: wrap;
  }

  &__tab {
    background: var(--bg-card);
    border: 1.5px solid var(--border);
    color: var(--text-secondary);
    border-radius: 8px;
    padding: 0.5rem 1.2rem;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    font-family: inherit;
    transition: all 0.2s;

    &.active, &:hover {
      border-color: var(--accent);
      color: var(--accent);
      background: rgba(16, 185, 129, 0.1);
    }
  }

  &__browser {
    border-radius: 14px;
    overflow: hidden;
    border: 1px solid var(--border-light);
    box-shadow: 0 40px 100px rgba(0, 0, 0, 0.7), 0 0 0 1px rgba(16, 185, 129, 0.08);
    animation: float 6s ease-in-out infinite;
  }

  &__titlebar {
    background: #1E293B;
    border-bottom: 1px solid var(--border);
    padding: 0.7rem 1.1rem;
    display: flex;
    align-items: center;
    gap: 0.4rem;
  }

  &__dot {
    width: 11px;
    height: 11px;
    border-radius: 50%;
    &--red    { background: #ff5f57; }
    &--yellow { background: #febc2e; }
    &--green  { background: #28c840; }
  }

  &__url {
    margin-left: 0.8rem;
    font-size: 0.78rem;
    color: var(--text-muted);
    background: var(--bg-elevated);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 0.2rem 0.75rem;
  }

  &__slide {
    display: none;
    &.active { display: block; }
  }

  &__svg {
    display: block;
    width: 100%;
    height: auto;
  }
}

/* ═══════════════════════════════════════════
   FEATURE SPOTLIGHTS
══════════════════════════════════════════════ */
.spotlight {
  padding: 7rem 0;
  background: var(--bg-base);

  &--alt {
    background: var(--bg-surface);
  }

  &__inner {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4rem;
    align-items: center;

    &--reversed {
      .spotlight__visual { order: -1; }
    }
  }

  &__text {
    .section-tag { margin-bottom: 1rem; display: block; }
    h2 {
      font-size: clamp(1.7rem, 3vw, 2.3rem);
      font-weight: 800;
      letter-spacing: -0.03em;
      color: var(--text-primary);
      margin-bottom: 1.1rem;
      line-height: 1.25;
    }
    p {
      color: var(--text-secondary);
      font-size: 1rem;
      line-height: 1.8;
      margin-bottom: 1.6rem;
    }
  }

  &__list {
    list-style: none;
    margin: 0 0 2rem;
    padding: 0;
    display: flex;
    flex-direction: column;
    gap: 0.7rem;

    li {
      display: flex;
      align-items: center;
      gap: 0.7rem;
      font-size: 0.93rem;
      color: var(--text-secondary);
      svg { width: 18px; height: 18px; flex-shrink: 0; }
    }
  }

  &__visual {
    position: relative;
  }
}

/* Projection chart demo card */
.proj-chart-demo {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: var(--shadow-lg);
  animation: float 7s ease-in-out infinite;

  &__header {
    background: var(--bg-elevated);
    border-bottom: 1px solid var(--border);
    padding: 0.85rem 1.2rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    font-size: 0.88rem;
    font-weight: 700;
    color: var(--text-primary);
  }

  &__legend {
    display: flex;
    align-items: center;
    gap: 1rem;
    font-size: 0.78rem;
    font-weight: 500;
    color: var(--text-secondary);
  }

  &__body {
    padding: 1rem 1.4rem 0;
    svg { width: 100%; height: auto; }
  }

  &__footer {
    display: flex;
    justify-content: space-between;
    padding: 1rem 1.4rem 1.2rem;
    border-top: 1px solid var(--border);
    flex-wrap: wrap;
    gap: 0.8rem;
  }
}

.dot-blue {
  width: 8px; height: 8px; border-radius: 50%;
  background: var(--accent); display: inline-block;
}
.dot-green {
  width: 8px; height: 8px; border-radius: 50%;
  background: var(--positive); display: inline-block;
}

.proj-stat {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;

  &__val {
    font-size: 0.95rem;
    font-weight: 700;
    color: var(--text-primary);
    &--green { color: var(--positive); }
    &--red   { color: var(--negative); }
  }
  &__lbl {
    font-size: 0.73rem;
    color: var(--text-muted);
  }
}

/* Projection chart SVG animations */
.anim-line-1 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.5s ease forwards 0.3s;
}
.anim-line-2 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.8s ease forwards 0.6s;
}
.proj-line-1 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.5s ease forwards 0.3s;
}
.proj-line-2 {
  stroke-dasharray: 900;
  stroke-dashoffset: 900;
  animation: drawLine 2.8s ease forwards 0.6s;
}

/* ═══════════════════════════════════════════
   IRISH TAX CARD
══════════════════════════════════════════════ */
.tax-card {
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 16px;
  overflow: hidden;
  box-shadow: var(--shadow-lg);
  animation: float 7s ease-in-out infinite 1s;

  &__header {
    background: var(--bg-elevated);
    border-bottom: 1px solid var(--border);
    padding: 1rem 1.4rem;
    font-size: 0.95rem;
    font-weight: 700;
    color: var(--text-primary);
  }

  &__body {
    padding: 0.8rem 1.4rem;
  }

  &__footer {
    background: var(--bg-elevated);
    border-top: 1px solid var(--border);
    padding: 0.75rem 1.4rem;
    font-size: 0.78rem;
    color: var(--text-muted);
    text-align: center;
  }
}

.tax-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 0.6rem 0;
  border-bottom: 1px solid rgba(229, 231, 235, 0.5);

  &:last-child { border-bottom: none; }

  &--divider { padding: 0.2rem 0; }

  &--total {
    margin-top: 0.3rem;
    border-top: 1px solid var(--border-light);
    padding-top: 0.9rem;
    .tax-row__label { font-weight: 700; color: var(--text-primary); }
    .tax-row__value { font-size: 1.1rem; font-weight: 800; }
  }

  &__label {
    font-size: 0.88rem;
    color: var(--text-secondary);
  }

  &__value {
    font-size: 0.92rem;
    font-weight: 600;
    color: var(--text-primary);
    &--pos { color: var(--positive); }
    &--neg { color: var(--negative); }
  }
}

.tax-badge {
  display: inline-block;
  background: rgba(240, 82, 82, 0.12);
  color: var(--negative);
  border: 1px solid rgba(240, 82, 82, 0.28);
  border-radius: 6px;
  padding: 0.2rem 0.6rem;
  font-size: 0.76rem;
  font-weight: 700;
}

/* ═══════════════════════════════════════════
   HOW IT WORKS
══════════════════════════════════════════════ */
.how {
  padding: 7rem 0;
  background: var(--bg-surface);

  &__steps {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    flex-wrap: wrap;
    gap: 1rem;
  }

  &__step {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 16px;
    padding: 2rem 1.8rem;
    flex: 1;
    min-width: 220px;
    max-width: 280px;
    text-align: center;
    transition: border-color 0.2s, transform 0.2s;

    &:hover {
      border-color: var(--accent);
      transform: translateY(-4px);
    }

    h3 {
      font-size: 1.05rem;
      font-weight: 700;
      color: var(--text-primary);
      margin-bottom: 0.6rem;
    }
    p {
      font-size: 0.88rem;
      color: var(--text-secondary);
      line-height: 1.7;
      margin: 0;
    }
  }

  &__step-num {
    font-size: 0.75rem;
    font-weight: 800;
    letter-spacing: 0.08em;
    color: var(--accent);
    opacity: 0.7;
    margin-bottom: 0.8rem;
  }

  &__step-icon {
    width: 52px;
    height: 52px;
    background: rgba(16, 185, 129, 0.1);
    border-radius: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0 auto 1.1rem;
    svg {
      width: 24px;
      height: 24px;
      stroke: var(--accent);
    }
  }

  &__connector {
    width: 48px;
    height: 1.5px;
    background: linear-gradient(90deg, transparent, var(--border-light), transparent);
    flex-shrink: 0;

    @media (max-width: 720px) { display: none; }
  }
}

/* ═══════════════════════════════════════════
   FINAL CTA
══════════════════════════════════════════════ */
.cta-section {
  position: relative;
  padding: 8rem 0;
  background: var(--bg-base);
  overflow: hidden;
  text-align: center;

  &__glow {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    width: 700px;
    height: 400px;
    background: radial-gradient(ellipse at center, rgba(16, 185, 129, 0.12) 0%, transparent 70%);
    pointer-events: none;
  }

  &__inner {
    position: relative;
    z-index: 1;

    h2 {
      font-size: clamp(1.9rem, 4vw, 2.9rem);
      font-weight: 900;
      letter-spacing: -0.03em;
      color: var(--text-primary);
      margin-bottom: 1rem;
    }
    p {
      color: var(--text-secondary);
      font-size: 1.05rem;
      margin-bottom: 2.4rem;
    }
  }

  &__btns {
    display: flex;
    justify-content: center;
    gap: 1rem;
    flex-wrap: wrap;
    margin-bottom: 1.4rem;
  }

  &__note {
    font-size: 0.82rem;
    color: var(--text-muted);
    margin-top: 1rem;
  }
}

/* ═══════════════════════════════════════════
   FOOTER
══════════════════════════════════════════════ */
.lp-footer {
  background: var(--bg-surface);
  border-top: 1px solid var(--border);
  padding: 2.5rem 0;

  &__inner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 1rem;
  }

  &__brand {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-weight: 700;
    color: var(--text-primary);
    font-size: 0.95rem;
  }
  &__brand-logo {
    height: 48px;
    width: auto;
    object-fit: contain;
  }
  &__icon { font-size: 1.2rem; }

  &__copy {
    color: var(--text-muted);
    font-size: 0.82rem;
    margin: 0;
  }

  &__links {
    display: flex;
    gap: 1.5rem;
    a {
      color: var(--text-secondary);
      text-decoration: none;
      font-size: 0.85rem;
      transition: color 0.15s;
      &:hover { color: var(--text-primary); }
    }
  }
}

/* ═══════════════════════════════════════════
   SIA ANNOUNCEMENT BANNER
══════════════════════════════════════════════ */
.sia-banner {
  background: linear-gradient(90deg, rgba(46,196,182,0.08) 0%, rgba(46,196,182,0.04) 100%);
  border-bottom: 1px solid rgba(46,196,182,0.2);
  padding: 0.85rem 0;

  &__inner {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-wrap: wrap;
  }

  &__flag { font-size: 1.4rem; flex-shrink: 0; }

  &__text {
    flex: 1;
    font-size: 0.88rem;
    color: var(--text-secondary);
    line-height: 1.5;
    strong { color: var(--text-primary); }
  }
}

.lp-btn--sia {
  background: rgba(46,196,182,0.15);
  color: #2ec4b6;
  border: 1.5px solid rgba(46,196,182,0.35);
  padding: 0.55rem 1.1rem;
  font-size: 0.85rem;
  white-space: nowrap;
  flex-shrink: 0;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
  font-family: inherit;
  transition: background 0.15s, transform 0.15s;
  &:hover { background: rgba(46,196,182,0.25); transform: translateY(-1px); }
}

/* ═══════════════════════════════════════════
   FEATURE CARD HIGHLIGHTED (SIA card)
══════════════════════════════════════════════ */
.feature-card--highlighted {
  border-color: rgba(46,196,182,0.35);
  background: linear-gradient(145deg, var(--bg-card) 0%, rgba(46,196,182,0.04) 100%);
  position: relative;

  &:hover { border-color: #2ec4b6; }
}

.feature-card__badge {
  position: absolute;
  top: 1rem;
  right: 1rem;
  background: rgba(46,196,182,0.15);
  color: #2ec4b6;
  border: 1px solid rgba(46,196,182,0.35);
  border-radius: 20px;
  padding: 0.18rem 0.65rem;
  font-size: 0.72rem;
  font-weight: 700;
  letter-spacing: 0.04em;
}

.feature-card__icon--emerald {
  background: rgba(46,196,182,0.12);
  color: #2ec4b6;
  svg { stroke: #2ec4b6; }
}

.section-tag--ireland {
  background: rgba(46,196,182,0.1);
  color: #2ec4b6;
  border-color: rgba(46,196,182,0.28);
}

/* ═══════════════════════════════════════════
   IRISH TAX PROBLEM SECTION
══════════════════════════════════════════════ */
.tax-problem {
  padding: 7rem 0;
  background: var(--bg-surface);
}

.tax-compare {
  display: grid;
  grid-template-columns: 1fr auto 1fr;
  gap: 0;
  align-items: stretch;
  margin-bottom: 3rem;

  @media (max-width: 900px) {
    grid-template-columns: 1fr;
  }

  &__card {
    border-radius: 16px;
    overflow: hidden;
    display: flex;
    flex-direction: column;

    &--problem {
      border: 1.5px solid rgba(240,82,82,0.35);
      background: var(--bg-card);
    }
    &--solution {
      border: 1.5px solid rgba(46,196,182,0.35);
      background: var(--bg-card);
    }
  }

  &__card-header {
    padding: 1.6rem 1.8rem 1.2rem;
    border-bottom: 1px solid var(--border);

    h3 {
      font-size: 1.2rem;
      font-weight: 800;
      color: var(--text-primary);
      margin: 0.5rem 0 0.3rem;
    }
    p {
      font-size: 0.85rem;
      color: var(--text-muted);
      margin: 0;
    }
  }

  &__card-body {
    padding: 0.5rem 1.8rem;
    flex: 1;
  }

  &__card-footer {
    padding: 0.9rem 1.8rem;
    font-size: 0.8rem;
    text-align: center;
    font-weight: 500;

    &--bad {
      background: rgba(240,82,82,0.07);
      border-top: 1px solid rgba(240,82,82,0.2);
      color: #f05252;
    }
    &--good {
      background: rgba(46,196,182,0.07);
      border-top: 1px solid rgba(46,196,182,0.2);
      color: #2ec4b6;
    }
  }

  &__regime-badge {
    display: inline-block;
    border-radius: 20px;
    padding: 0.22rem 0.75rem;
    font-size: 0.75rem;
    font-weight: 700;
    letter-spacing: 0.04em;

    &--current {
      background: rgba(240,82,82,0.12);
      color: #f05252;
      border: 1px solid rgba(240,82,82,0.3);
    }
    &--sia {
      background: rgba(46,196,182,0.12);
      color: #2ec4b6;
      border: 1px solid rgba(46,196,182,0.3);
    }
  }

  &__row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.65rem 0;
    border-bottom: 1px solid rgba(229,231,235,0.4);
    gap: 1rem;
    flex-wrap: wrap;

    &:last-child { border-bottom: none; }
  }

  &__label {
    font-size: 0.84rem;
    color: var(--text-secondary);
    flex-shrink: 0;
  }

  &__value {
    font-size: 0.84rem;
    font-weight: 600;
    color: var(--text-primary);
    text-align: right;

    &--bad  { color: #f05252; }
    &--good { color: #2ec4b6; }
  }

  &__vs {
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    padding: 0 1.5rem;
    gap: 0.5rem;

    span {
      font-size: 1.1rem;
      font-weight: 900;
      color: var(--text-muted);
      letter-spacing: 0.1em;
    }

    @media (max-width: 900px) {
      flex-direction: row;
      padding: 1rem 0;
    }
  }

  &__arrow {
    font-size: 1.4rem;
    color: rgba(16,185,129,0.4);
    @media (max-width: 900px) { transform: rotate(90deg); }
  }

  &__year {
    background: rgba(16,185,129,0.12);
    color: var(--accent);
    border: 1px solid rgba(16,185,129,0.25);
    border-radius: 20px;
    padding: 0.2rem 0.65rem;
    font-size: 0.8rem !important;
    font-weight: 700 !important;
    letter-spacing: 0.04em;
  }
}

.tax-cta {
  display: flex;
  align-items: center;
  gap: 2rem;
  background: var(--bg-card);
  border: 1px solid var(--border-light);
  border-radius: 14px;
  padding: 1.6rem 2rem;
  flex-wrap: wrap;

  &__text {
    flex: 1;
    font-size: 0.93rem;
    color: var(--text-secondary);
    line-height: 1.7;
    strong { color: var(--text-primary); }
  }
}

/* ═══════════════════════════════════════════
   FOR GLOBAL INVESTORS
══════════════════════════════════════════════ */
.global-investors {
  padding: 7rem 0;
  background: var(--bg-base);
}

.global-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
  gap: 1.25rem;
}

.global-card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 1.8rem;
  transition: border-color 0.2s, box-shadow 0.2s, transform 0.2s;

  &:hover {
    border-color: var(--border-light);
    box-shadow: var(--shadow-lg);
    transform: translateY(-3px);
  }

  &__icon {
    width: 46px;
    height: 46px;
    border-radius: 12px;
    background: rgba(16,185,129,0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 1.1rem;
    svg { width: 22px; height: 22px; stroke: var(--accent); }
  }

  h3 {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 0.5rem;
  }
  p {
    font-size: 0.9rem;
    color: var(--text-secondary);
    line-height: 1.7;
    margin: 0;
  }
}

/* CTA tagline */
.cta-section__tagline {
  font-size: 0.88rem;
  color: #2ec4b6;
  margin-top: -1rem;
  margin-bottom: 2rem;
  font-weight: 500;
}

/* ═══════════════════════════════════════════
   KEYFRAMES
══════════════════════════════════════════════ */
@keyframes drawLine {
  to { stroke-dashoffset: 0; }
}

@keyframes pulse {
  0%, 100% { transform: scale(1); opacity: 1; }
  50%       { transform: scale(1.6); opacity: 0.5; }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes bob {
  0%, 100% { transform: translateX(-50%) translateY(0); }
  50%       { transform: translateX(-50%) translateY(6px); }
}

@keyframes float {
  0%, 100% { transform: translateY(0); }
  50%       { transform: translateY(-8px); }
}

/* ═══════════════════════════════════════════
   RESPONSIVE
══════════════════════════════════════════════ */
@media (max-width: 900px) {
  .spotlight__inner {
    grid-template-columns: 1fr;
    gap: 2.5rem;

    &--reversed .spotlight__visual { order: unset; }
  }

  .lp-nav__links { display: none; }

  .hero__content { padding-top: 6rem; }
}

@media (max-width: 600px) {
  .hero__stats { flex-direction: column; gap: 1rem; }
  .hero__stat-sep { display: none; }
  .features__grid { grid-template-columns: 1fr; }
  .lp-footer__inner { flex-direction: column; text-align: center; }
  .how__steps { flex-direction: column; align-items: center; }
  .how__connector { display: none; }
}

