    .login-container {
      min-height: 100vh;
      display: flex;
      align-items: center;
      justify-content: center;
      background: var(--bg-surface);
    }
    .login-card {
      background: var(--bg-card);
      border: 1px solid var(--border-light);
      border-radius: 16px;
      padding: 2.5rem 2rem;
      width: 380px;
      text-align: center;
      box-shadow: var(--shadow-lg);
    }
    .brand { margin-bottom: 1.5rem; }
    .brand-icon { font-size: 2.5rem; display: block; margin-bottom: 0.75rem; }
    h1 { font-size: 1.35rem; font-weight: 700; margin: 0 0 0.4rem; color: var(--text-primary); }
    .subtitle { color: var(--text-muted); font-size: 0.88rem; margin: 0; }

    .error-banner {
      background: var(--negative-bg);
      color: var(--negative);
      border: 1px solid rgba(240,82,82,0.3);
      border-radius: 8px;
      padding: 0.75rem;
      margin-bottom: 1rem;
      font-size: 0.88rem;
    }
    .success-banner {
      background: rgba(52,211,153,0.1);
      color: #34d399;
      border: 1px solid rgba(52,211,153,0.3);
      border-radius: 8px;
      padding: 0.75rem;
      margin-bottom: 1rem;
      font-size: 0.88rem;
    }

    .email-form {
      display: flex;
      flex-direction: column;
      gap: 0.65rem;
      margin-bottom: 0.75rem;
